"use server";

import { prisma } from "@/lib/db";
import { requireAdmin } from "@/lib/auth-helpers";
import { revalidatePath } from "next/cache";

export type DuplicateRemovalResult = {
    success: boolean;
    totalFound: number;
    removed: number;
    skipped: number;
    error?: string;
    details?: string[];
};

export type DuplicateGroup = {
    text: string;
    questions: {
        id: string;
        topicName: string; // "Skill"
        createdAt: Date;
        usageCount: {
            userAnswers: number;
            quizPools: number;
        };
    }[];
    hasTopicConflict: boolean;
};

export async function getDuplicateGroups(): Promise<DuplicateGroup[]> {
    try {
        await requireAdmin();

        const allQuestions = await prisma.question.findMany({
            select: {
                id: true,
                questionText: true,
                createdAt: true,
                topic: {
                    select: { name: true }
                },
                _count: {
                    select: {
                        userAnswers: true,
                        quizPools: true,
                    }
                }
            },
            orderBy: { createdAt: "asc" },
        });

        const groups = new Map<string, typeof allQuestions>();
        for (const q of allQuestions) {
            const normalizedText = q.questionText.trim().toLowerCase();
            if (!groups.has(normalizedText)) {
                groups.set(normalizedText, []);
            }
            groups.get(normalizedText)!.push(q);
        }

        const duplicateGroups: DuplicateGroup[] = [];

        for (const [text, questions] of groups.entries()) {
            if (questions.length <= 1) continue;

            // Check for topic conflict
            const topicNames = new Set(questions.map(q => q.topic.name));
            const hasTopicConflict = topicNames.size > 1;

            duplicateGroups.push({
                text: questions[0].questionText, // Use the first one's text for display
                questions: questions.map(q => ({
                    id: q.id,
                    topicName: q.topic.name,
                    createdAt: q.createdAt,
                    usageCount: q._count
                })),
                hasTopicConflict
            });
        }

        return duplicateGroups;

    } catch (error) {
        console.error("Error fetching duplicate groups:", error);
        throw new Error("Failed to fetch duplicates");
    }
}

export async function resolveDuplicateGroup(keepId: string, removeIds: string[]): Promise<{ success: boolean; error?: string }> {
    try {
        await requireAdmin();

        const keep = await prisma.question.findUnique({ where: { id: keepId } });
        if (!keep) throw new Error("Target question not found");

        await prisma.$transaction(async (tx) => {
            // 1. Map Answers (from all removed questions to the keep question)
            const origAnswers = await tx.answer.findMany({ where: { questionId: keep.id } });

            for (const removeId of removeIds) {
                const dupAnswers = await tx.answer.findMany({ where: { questionId: removeId } });

                const answerMap = new Map<string, string>();
                for (const dAns of dupAnswers) {
                    const match = origAnswers.find(o =>
                        o.answerText.trim().toLowerCase() === dAns.answerText.trim().toLowerCase()
                    );
                    if (match) {
                        answerMap.set(dAns.id, match.id);
                    }
                }

                // 2. Move UserAnswers
                const dupUserAnswers = await tx.userAnswer.findMany({ where: { questionId: removeId } });

                if (dupUserAnswers.length > 0) {
                    const attemptIds = Array.from(new Set(dupUserAnswers.map(ua => ua.attemptId)));
                    const conflictAnswers = await tx.userAnswer.findMany({
                        where: {
                            questionId: keep.id,
                            attemptId: { in: attemptIds }
                        },
                        select: { attemptId: true }
                    });

                    const attemptIdsWithOrig = new Set(conflictAnswers.map(a => a.attemptId));

                    for (const ua of dupUserAnswers) {
                        if (attemptIdsWithOrig.has(ua.attemptId)) {
                            await tx.userAnswer.delete({ where: { id: ua.id } });
                        } else {
                            const newAnswerId = ua.answerId ? answerMap.get(ua.answerId) : null;
                            await tx.userAnswer.update({
                                where: { id: ua.id },
                                data: {
                                    questionId: keep.id,
                                    answerId: newAnswerId ?? null
                                }
                            });
                        }
                    }
                }

                // 3. Move QuizPools
                const dupPools = await tx.quizQuestionPool.findMany({ where: { questionId: removeId } });
                for (const pool of dupPools) {
                    const conflict = await tx.quizQuestionPool.findUnique({
                        where: { quizId_questionId: { quizId: pool.quizId, questionId: keep.id } }
                    });

                    if (conflict) {
                        await tx.quizQuestionPool.delete({ where: { id: pool.id } });
                    } else {
                        await tx.quizQuestionPool.update({
                            where: { id: pool.id },
                            data: { questionId: keep.id }
                        });
                    }
                }

                // 4. Move Reports
                await tx.questionReport.updateMany({
                    where: { questionId: removeId },
                    data: { questionId: keep.id }
                });

                // 5. Update QuizAttempts
                const attemptsWithDup = await tx.quizAttempt.findMany({
                    where: { selectedQuestionIds: { has: removeId } },
                    select: { id: true, selectedQuestionIds: true }
                });

                for (const attempt of attemptsWithDup) {
                    const newIds = attempt.selectedQuestionIds.map(id =>
                        id === removeId ? keep.id : id
                    );
                    const uniqueIds = Array.from(new Set(newIds));

                    await tx.quizAttempt.update({
                        where: { id: attempt.id },
                        data: { selectedQuestionIds: uniqueIds }
                    });
                }

                // 6. Delete the Duplicate
                await tx.question.delete({ where: { id: removeId } });
            }
        }, {
            timeout: 20000,
            maxWait: 5000
        });

        revalidatePath("/admin/questions");
        return { success: true };

    } catch (error: any) {
        console.error("Error resolving duplicate group:", error);
        return { success: false, error: error.message };
    }
}

export async function findAndRemoveDuplicateQuestions(): Promise<DuplicateRemovalResult> {
    try {
        await requireAdmin();

        // 1. Fetch all questions (id, text, createdAt)
        // For very large datasets, this should be paginated or done via raw SQL,
        // but for typical admin usage (<10k questions), this in-memory approach is acceptable and safer.
        const allQuestions = await prisma.question.findMany({
            select: {
                id: true,
                questionText: true,
                createdAt: true,
            },
            orderBy: {
                createdAt: "asc", // Oldest first
            },
        });

        // 2. Group by questionText
        const groups = new Map<string, typeof allQuestions>();

        for (const q of allQuestions) {
            // Normalize text: trim and lowercase for better matching
            const normalizedText = q.questionText.trim().toLowerCase();

            if (!groups.has(normalizedText)) {
                groups.set(normalizedText, []);
            }
            groups.get(normalizedText)!.push(q);
        }

        let totalFound = 0;
        let removed = 0;
        let skipped = 0;
        const details: string[] = [];

        // 3. Process duplicates
        for (const [text, questions] of groups.entries()) {
            if (questions.length <= 1) continue;

            // Found duplicates
            const duplicatesCount = questions.length - 1;
            totalFound += duplicatesCount;

            // Keep the first one (oldest because of query order)
            const [keep, ...toRemove] = questions;

            for (const q of toRemove) {
                try {
                    // Merge q (duplicate) into keep (original)
                    await prisma.$transaction(async (tx) => {
                        // 1. Map Answers
                        const origAnswers = await tx.answer.findMany({ where: { questionId: keep.id } });
                        const dupAnswers = await tx.answer.findMany({ where: { questionId: q.id } });

                        const answerMap = new Map<string, string>(); // dupAnswerId -> origAnswerId
                        for (const dAns of dupAnswers) {
                            const match = origAnswers.find(o =>
                                o.answerText.trim().toLowerCase() === dAns.answerText.trim().toLowerCase()
                            );
                            if (match) {
                                answerMap.set(dAns.id, match.id);
                            }
                        }

                        // 2. Move UserAnswers (Optimized)
                        const dupUserAnswers = await tx.userAnswer.findMany({ where: { questionId: q.id } });

                        if (dupUserAnswers.length > 0) {
                            const attemptIds = Array.from(new Set(dupUserAnswers.map(ua => ua.attemptId)));
                            // Batch fetch existing answers to the MAIN question in these attempts
                            const conflictAnswers = await tx.userAnswer.findMany({
                                where: {
                                    questionId: keep.id,
                                    attemptId: { in: attemptIds }
                                },
                                select: { attemptId: true }
                            });

                            const attemptIdsWithOrig = new Set(conflictAnswers.map(a => a.attemptId));

                            for (const ua of dupUserAnswers) {
                                if (attemptIdsWithOrig.has(ua.attemptId)) {
                                    // Conflict: delete duplicate answer
                                    await tx.userAnswer.delete({ where: { id: ua.id } });
                                } else {
                                    // No conflict: move to original
                                    const newAnswerId = ua.answerId ? answerMap.get(ua.answerId) : null;
                                    await tx.userAnswer.update({
                                        where: { id: ua.id },
                                        data: {
                                            questionId: keep.id,
                                            answerId: newAnswerId ?? null
                                        }
                                    });
                                }
                            }
                        }

                        // 3. Move QuizPools
                        const dupPools = await tx.quizQuestionPool.findMany({ where: { questionId: q.id } });
                        for (const pool of dupPools) {
                            const conflict = await tx.quizQuestionPool.findUnique({
                                where: { quizId_questionId: { quizId: pool.quizId, questionId: keep.id } }
                            });

                            if (conflict) {
                                // Redundant inclusion in same quiz
                                await tx.quizQuestionPool.delete({ where: { id: pool.id } });
                            } else {
                                await tx.quizQuestionPool.update({
                                    where: { id: pool.id },
                                    data: { questionId: keep.id }
                                });
                            }
                        }

                        // 4. Move Reports
                        await tx.questionReport.updateMany({
                            where: { questionId: q.id },
                            data: { questionId: keep.id }
                        });

                        // 5. Update QuizAttempts (selectedQuestionIds array)
                        // This identifies attempts that have the DUPLICATE question in their list
                        const attemptsWithDup = await tx.quizAttempt.findMany({
                            where: { selectedQuestionIds: { has: q.id } },
                            select: { id: true, selectedQuestionIds: true }
                        });

                        for (const attempt of attemptsWithDup) {
                            // Replace dup ID with original ID
                            const newIds = attempt.selectedQuestionIds.map(id =>
                                id === q.id ? keep.id : id
                            );
                            // Ensure uniqueness (in case both were present)
                            const uniqueIds = Array.from(new Set(newIds));

                            await tx.quizAttempt.update({
                                where: { id: attempt.id },
                                data: { selectedQuestionIds: uniqueIds }
                            });
                        }

                        // 6. Delete the Duplicate Question
                        await tx.question.delete({ where: { id: q.id } });
                    }, {
                        timeout: 20000, // Increase timeout to 20s
                        maxWait: 5000
                    });

                    removed++;
                    // Optional: Add details about merged dependencies if needed, 
                    // but for now we treat it as a successful removal.
                } catch (error: any) {
                    // Handle generic errors
                    console.error(`Failed to merge/delete question ${q.id}:`, error);
                    skipped++;
                    details.push(`Error merging "${q.questionText.substring(0, 30)}..." (ID: ${q.id}) - ${error.message}`);
                }
            }
        }

        revalidatePath("/admin/questions");

        return {
            success: true,
            totalFound,
            removed,
            skipped,
            details: details.length > 0 ? details.slice(0, 10) : undefined, // Return first 10 details to avoid huge payload
        };

    } catch (error: any) {
        console.error("Error in findAndRemoveDuplicateQuestions:", error);
        return {
            success: false,
            totalFound: 0,
            removed: 0,
            skipped: 0,
            error: error.message || "An unexpected error occurred",
        };
    }
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import { Plus, Calendar, Trash2, Edit2, RefreshCw, Upload } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from '@/components/ui/dialog';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import { useToast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';
import type { DailyGameType } from '@/lib/utils/daily-game-logic';

interface DailyGame {
    id: string;
    date: string;
    gameType: DailyGameType;
    targetValue: string;
    clues: unknown | null;
    _count?: { attempts: number };
}

interface DailyGamesAdminClientProps {
    initialGames: DailyGame[];
}

const gameTypeLabels: Record<DailyGameType, string> = {
    WORD: 'Word Puzzle',
    ATHLETE: 'Mystery Athlete',
    TEAM: 'Mystery Team',
    STAT: 'Stat Challenge',
};

const gameTypeBadgeVariants: Record<DailyGameType, string> = {
    WORD: 'bg-emerald-500/10 text-emerald-600 border-emerald-500/20',
    ATHLETE: 'bg-orange-500/10 text-orange-600 border-orange-500/20',
    TEAM: 'bg-blue-500/10 text-blue-600 border-blue-500/20',
    STAT: 'bg-purple-500/10 text-purple-600 border-purple-500/20',
};

export function DailyGamesAdminClient({ initialGames }: DailyGamesAdminClientProps) {
    const [games, setGames] = useState<DailyGame[]>(initialGames);
    const [isLoading, setIsLoading] = useState(false);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingGame, setEditingGame] = useState<DailyGame | null>(null);
    const { toast } = useToast();

    // Form state
    const [formData, setFormData] = useState({
        date: '',
        gameType: 'WORD' as DailyGameType,
        targetValue: '',
        clues: '',
    });

    const resetForm = () => {
        setFormData({
            date: '',
            gameType: 'WORD',
            targetValue: '',
            clues: '',
        });
        setEditingGame(null);
    };

    const handleOpenDialog = (game?: DailyGame) => {
        if (game) {
            setEditingGame(game);
            setFormData({
                date: game.date,
                gameType: game.gameType,
                targetValue: game.targetValue,
                clues: game.clues ? JSON.stringify(game.clues, null, 2) : '',
            });
        } else {
            resetForm();
        }
        setIsDialogOpen(true);
    };

    const handleSubmit = async () => {
        if (!formData.date || !formData.targetValue) {
            toast({
                title: 'Validation Error',
                description: 'Date and target value are required',
                variant: 'destructive',
            });
            return;
        }

        setIsLoading(true);

        try {
            let clues = null;
            if (formData.clues.trim()) {
                try {
                    clues = JSON.parse(formData.clues);
                } catch {
                    toast({
                        title: 'Invalid JSON',
                        description: 'Clues must be valid JSON',
                        variant: 'destructive',
                    });
                    return;
                }
            }

            const response = await fetch('/api/admin/daily', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    date: formData.date,
                    gameType: formData.gameType,
                    targetValue: formData.targetValue,
                    clues,
                }),
            });

            if (!response.ok) {
                const data = await response.json();
                throw new Error(data.error || 'Failed to save game');
            }

            const { game } = await response.json();

            setGames(prev => {
                const existing = prev.findIndex(g => g.date === game.date);
                if (existing >= 0) {
                    const updated = [...prev];
                    updated[existing] = game;
                    return updated;
                }
                return [...prev, game].sort((a, b) => a.date.localeCompare(b.date));
            });

            toast({
                title: 'Success',
                description: editingGame ? 'Game updated' : 'Game created',
            });

            setIsDialogOpen(false);
            resetForm();
        } catch (error) {
            toast({
                title: 'Error',
                description: error instanceof Error ? error.message : 'Failed to save game',
                variant: 'destructive',
            });
        } finally {
            setIsLoading(false);
        }
    };

    const handleDelete = async (game: DailyGame) => {
        if (!confirm(`Delete game for ${game.date}?`)) return;

        setIsLoading(true);

        try {
            const response = await fetch(`/api/admin/daily?id=${game.id}`, {
                method: 'DELETE',
            });

            if (!response.ok) {
                throw new Error('Failed to delete game');
            }

            setGames(prev => prev.filter(g => g.id !== game.id));

            toast({
                title: 'Deleted',
                description: `Game for ${game.date} has been deleted`,
            });
        } catch (error) {
            toast({
                title: 'Error',
                description: 'Failed to delete game',
                variant: 'destructive',
            });
        } finally {
            setIsLoading(false);
        }
    };

    const handleAutoSchedule = async () => {
        if (!confirm('This will auto-schedule games for the next 30 days. Continue?')) return;

        setIsLoading(true);

        try {
            const response = await fetch('/api/cron/daily-games', {
                method: 'POST',
                headers: { 'x-cron-secret': 'manual-trigger' },
            });

            if (!response.ok) {
                throw new Error('Failed to auto-schedule');
            }

            // Refresh games list
            const gamesResponse = await fetch('/api/admin/daily');
            const { games: newGames } = await gamesResponse.json();
            setGames(newGames);

            toast({
                title: 'Success',
                description: 'Games have been auto-scheduled',
            });
        } catch (error) {
            toast({
                title: 'Error',
                description: 'Failed to auto-schedule games',
                variant: 'destructive',
            });
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            {/* Actions */}
            <div className="flex gap-3">
                <Link href="/admin/daily/import">
                    <Button variant="outline" disabled={isLoading}>
                        <Upload className="w-4 h-4 mr-2" />
                        Import Word Puzzles
                    </Button>
                </Link>

                <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                    <DialogTrigger asChild>
                        <Button onClick={() => handleOpenDialog()}>
                            <Plus className="w-4 h-4 mr-2" />
                            Add Game
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="max-w-lg">
                        <DialogHeader>
                            <DialogTitle>{editingGame ? 'Edit Game' : 'Add New Game'}</DialogTitle>
                            <DialogDescription>
                                {editingGame ? 'Update the daily game details' : 'Schedule a new daily game'}
                            </DialogDescription>
                        </DialogHeader>

                        <div className="space-y-4 py-4">
                            <div className="space-y-2">
                                <Label htmlFor="date">Date</Label>
                                <Input
                                    id="date"
                                    type="date"
                                    value={formData.date}
                                    onChange={(e) => setFormData(prev => ({ ...prev, date: e.target.value }))}
                                    disabled={!!editingGame}
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="gameType">Game Type</Label>
                                <Select
                                    value={formData.gameType}
                                    onValueChange={(value) => setFormData(prev => ({ ...prev, gameType: value as DailyGameType }))}
                                >
                                    <SelectTrigger>
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="WORD">Word Puzzle</SelectItem>
                                        <SelectItem value="ATHLETE">Mystery Athlete</SelectItem>
                                        <SelectItem value="TEAM">Mystery Team</SelectItem>
                                        <SelectItem value="STAT">Stat Challenge</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="targetValue">Target Value / Answer</Label>
                                <Input
                                    id="targetValue"
                                    value={formData.targetValue}
                                    onChange={(e) => setFormData(prev => ({ ...prev, targetValue: e.target.value }))}
                                    placeholder={formData.gameType === 'WORD' ? 'SCORE' : 'Answer...'}
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="clues">Clues (JSON)</Label>
                                <Textarea
                                    id="clues"
                                    value={formData.clues}
                                    onChange={(e) => setFormData(prev => ({ ...prev, clues: e.target.value }))}
                                    placeholder='{"hint": "...", "player": "..."}'
                                    rows={4}
                                    className="font-mono text-sm"
                                />
                            </div>
                        </div>

                        <DialogFooter>
                            <Button variant="outline" onClick={() => setIsDialogOpen(false)}>
                                Cancel
                            </Button>
                            <Button onClick={handleSubmit} disabled={isLoading}>
                                {isLoading ? 'Saving...' : editingGame ? 'Update' : 'Create'}
                            </Button>
                        </DialogFooter>
                    </DialogContent>
                </Dialog>

                <Button variant="outline" onClick={handleAutoSchedule} disabled={isLoading}>
                    <RefreshCw className={cn("w-4 h-4 mr-2", isLoading && "animate-spin")} />
                    Auto-Schedule 30 Days
                </Button>
            </div>

            {/* Games Table */}
            <div className="border rounded-lg overflow-hidden">
                <Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>Date</TableHead>
                            <TableHead>Type</TableHead>
                            <TableHead>Answer</TableHead>
                            <TableHead>Attempts</TableHead>
                            <TableHead className="w-24">Actions</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {games.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={5} className="text-center py-8 text-muted-foreground">
                                    No games scheduled. Click &quot;Add Game&quot; or &quot;Auto-Schedule&quot; to get started.
                                </TableCell>
                            </TableRow>
                        ) : (
                            games.map((game) => (
                                <TableRow key={game.id}>
                                    <TableCell className="font-medium">
                                        <div className="flex items-center gap-2">
                                            <Calendar className="w-4 h-4 text-muted-foreground" />
                                            {game.date}
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <Badge variant="outline" className={gameTypeBadgeVariants[game.gameType]}>
                                            {gameTypeLabels[game.gameType]}
                                        </Badge>
                                    </TableCell>
                                    <TableCell className="font-mono text-sm">
                                        {game.targetValue.length > 20
                                            ? game.targetValue.substring(0, 20) + '...'
                                            : game.targetValue}
                                    </TableCell>
                                    <TableCell>{game._count?.attempts ?? 0}</TableCell>
                                    <TableCell>
                                        <div className="flex items-center gap-1">
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => handleOpenDialog(game)}
                                            >
                                                <Edit2 className="w-4 h-4" />
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => handleDelete(game)}
                                                className="text-destructive hover:text-destructive"
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </Button>
                                        </div>
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { PageHeader } from "@/components/shared/PageHeader";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";
import { Upload, FileJson, CheckCircle, AlertCircle } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";

export default function ImportPage() {
  const router = useRouter();
  const { toast } = useToast();
  const [jsonInput, setJsonInput] = useState("");
  const [validating, setValidating] = useState(false);
  const [importing, setImporting] = useState(false);
  const [validationResult, setValidationResult] = useState<any>(null);
  const [preview, setPreview] = useState<any>(null);

  const validateJSON = () => {
    setValidating(true);
    setValidationResult(null);
    setPreview(null);

    try {
      const parsed = JSON.parse(jsonInput);

      // Basic validation
      const errors: string[] = [];

      if (!parsed.title) errors.push("Title is required");

      if (parsed.playMode === "GRID_3X3") {
        errors.push("Grid import is no longer supported here. Use the dedicated Import Grid page at /admin/grids/import");
      } else {
        if (!parsed.questions || !Array.isArray(parsed.questions)) {
          errors.push("Questions array is required");
        }
        if (parsed.questions && parsed.questions.length === 0) {
          errors.push("At least one question is required");
        }

        // Validate each question
        parsed.questions?.forEach((q: any, idx: number) => {
          if (!q.text) errors.push(`Question ${idx + 1}: text is required`);
          if (!q.answers || q.answers.length < 2) {
            errors.push(`Question ${idx + 1}: at least 2 answers required`);
          }

          const correctAnswers = q.answers?.filter((a: any) => a.isCorrect);
          if (correctAnswers?.length !== 1) {
            errors.push(`Question ${idx + 1}: exactly one correct answer required`);
          }
        });
      }

      if (errors.length > 0) {
        setValidationResult({ valid: false, errors });
      } else {
        setValidationResult({ valid: true, errors: [] });
        setPreview(parsed);
      }
    } catch (error: any) {
      setValidationResult({
        valid: false,
        errors: ["Invalid JSON format: " + error.message],
      });
    } finally {
      setValidating(false);
    }
  };

  const handleImport = async () => {
    if (!preview) return;

    setImporting(true);

    try {
      const response = await fetch("/api/admin/quizzes/import", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(preview),
      });

      const result = await response.json();

