          {/* Actions moved to sticky bar */}
        </form>

      </div>

      {/* Delete Confirmation Dialog */}
      <Dialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Delete Quiz</DialogTitle>
            <DialogDescription>
              Are you sure you want to delete &quot;{formData.title}&quot;? This will archive the quiz and it will no longer be visible to users.
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteDialogOpen(false)}>
              Cancel
            </Button>
            <Button variant="destructive" onClick={handleDelete} disabled={deleting}>
              {deleting ? "Deleting..." : "Delete Quiz"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import { Fragment, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { PageHeader } from "@/components/shared/PageHeader";
import { Button } from "@/components/ui/button";
import { Plus, Edit, Trash2, ChevronRight, ChevronDown, GitMerge, Check, ChevronsUpDown } from "lucide-react";
import Link from "next/link";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { cn } from "@/lib/utils";

interface TopicNode {
  id: string;
  name: string;
  slug: string;
  description?: string | null;
  level: number;
  parent?: { name: string } | null;
  children?: TopicNode[];
  _count: {
    questions: number;
    children: number;
    quizTopicConfigs: number;
  };
}

interface AdminTopicsClientProps {
  topics: TopicNode[];
}

export function AdminTopicsClient({ topics }: AdminTopicsClientProps) {
  const { toast } = useToast();
  const router = useRouter();
  const [expandedTopics, setExpandedTopics] = useState<Set<string>>(new Set());
  const [deleting, setDeleting] = useState(false);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [topicToDelete, setTopicToDelete] = useState<TopicNode | null>(null);
  const [mergeDialogOpen, setMergeDialogOpen] = useState(false);
  const [topicToMerge, setTopicToMerge] = useState<TopicNode | null>(null);
  const [destinationTopicId, setDestinationTopicId] = useState<string>("");
  const [merging, setMerging] = useState(false);
  const [comboboxOpen, setComboboxOpen] = useState(false);

  const totalTopics = useMemo(() => topics.length, [topics]);

  const toggleExpand = (topicId: string) => {
    setExpandedTopics((prev) => {
      const next = new Set(prev);
      if (next.has(topicId)) {
        next.delete(topicId);
      } else {
        next.add(topicId);
      }
      return next;
    });
  };

  const handleDelete = async () => {
    if (!topicToDelete) return;

    setDeleting(true);
    try {
      const response = await fetch(`/api/admin/topics/${topicToDelete.id}`, {
        method: "DELETE",
      });
      const result = await response.json();

      if (!response.ok || !result.data?.message?.includes("successfully")) {
        toast({
          title: "Cannot Delete Topic",
          description: result.data?.message || result.error || "Failed to delete topic",
          variant: "destructive",
        });
      } else {
        toast({
          title: "Topic deleted!",
          description: "The topic has been removed successfully.",
        });
        router.refresh();
      }

      setDeleteDialogOpen(false);
      setTopicToDelete(null);
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setDeleting(false);
    }
  };

  const openDeleteDialog = (topic: TopicNode) => {
    setTopicToDelete(topic);
    setDeleteDialogOpen(true);
  };

  const openMergeDialog = (topic: TopicNode) => {
    setTopicToMerge(topic);
    setDestinationTopicId("");
    setComboboxOpen(false);
    setMergeDialogOpen(true);
  };

  const handleMerge = async () => {
    if (!topicToMerge || !destinationTopicId) return;

    setMerging(true);
    try {
      const response = await fetch(`/api/admin/topics/${topicToMerge.id}/merge`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ destinationId: destinationTopicId }),
      });
      const result = await response.json();

      if (!response.ok) {
        toast({
          title: "Merge Failed",
          description: result.error || "Failed to merge topics",
          variant: "destructive",
        });
      } else {
        toast({
          title: "Topics Merged!",
          description: "Resources have been moved and the source topic was deleted.",
        });
        setMergeDialogOpen(false);
        setTopicToMerge(null);
        router.refresh();
      }
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setMerging(false);
    }
  };

  // Flattened topics for merge selection, excluding the source topic and its descendants
  const getMergeableTopics = (sourceTopicId: string) => {
    // Simple recursive function to find descendants
    const getDescendantIds = (topic: TopicNode): string[] => {
      const ids = [topic.id];
      topic.children?.forEach(child => {
        ids.push(...getDescendantIds(child));
      });
      return ids;
    };


    // Better to just filter from the full flattened list if we had one. 
    // For now, let's just do a basic filter on top-level topics for simplicity or assume user knows
    // In a real app we'd have a flattened list or searchable select.

    const flatten = (nodes: TopicNode[]): TopicNode[] => {
      return nodes.reduce((acc: TopicNode[], node) => {
        return acc.concat([node], flatten(node.children || []));
      }, []);
    };

    const allFlattened = flatten(topics);
    const sourceNode = allFlattened.find(n => n.id === sourceTopicId);
    if (!sourceNode) return allFlattened;

    const sourceAndDescendantIds = getDescendantIds(sourceNode);
    return allFlattened.filter(t => !sourceAndDescendantIds.includes(t.id));
  };

  const renderTopicRow = (topic: TopicNode, depth: number = 0) => {
    const hasChildren = (topic.children?.length ?? 0) > 0;
    const isExpanded = expandedTopics.has(topic.id);

    return (
      <Fragment key={topic.id}>
        <TableRow>
          <TableCell>
            <div className="flex items-center gap-2" style={{ paddingLeft: `${depth * 24}px` }}>
              {hasChildren ? (
                <Button
                  variant="ghost"
                  size="sm"
                  className="h-6 w-6 p-0"
                  onClick={() => toggleExpand(topic.id)}
                >
                  {isExpanded ? (
                    <ChevronDown className="h-4 w-4" />
                  ) : (
                    <ChevronRight className="h-4 w-4" />
                  )}
                </Button>
              ) : (
                <div className="w-6" />
              )}
              <span className="font-medium">{topic.name}</span>
            </div>
          </TableCell>
          <TableCell>
            <code className="text-xs bg-muted px-2 py-1 rounded">{topic.slug}</code>
          </TableCell>
          <TableCell>
            {topic.parent ? (
              <Badge variant="outline">{topic.parent.name}</Badge>
            ) : (
              <Badge>Root</Badge>
            )}
          </TableCell>
          <TableCell className="text-center">
            <Badge variant="secondary">{topic.level}</Badge>
          </TableCell>
          <TableCell className="text-right">{topic._count.questions}</TableCell>
          <TableCell className="text-right">{topic._count.children}</TableCell>
          <TableCell className="text-right">{topic._count.quizTopicConfigs}</TableCell>
          <TableCell className="text-right">
            <div className="flex justify-end gap-2">
              <Link href={`/admin/topics/${topic.id}/edit`}>
                <Button variant="outline" size="sm">
                  <Edit className="h-4 w-4" />
                </Button>
              </Link>
              <Button
                variant="outline"
                size="sm"
                onClick={() => openMergeDialog(topic)}
                title="Merge into another topic"
              >
                <GitMerge className="h-4 w-4 text-blue-500" />
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={() => openDeleteDialog(topic)}
              >
                <Trash2 className="h-4 w-4 text-destructive" />
              </Button>
            </div>
          </TableCell>
        </TableRow>
        {hasChildren &&
          isExpanded &&
          topic.children?.map((child) => renderTopicRow(child, depth + 1))}
      </Fragment>
    );
  };

  return (
    <div>
      <PageHeader
        title="Topics"
        description="Manage topic hierarchy for categorizing questions"
        action={
          <Link href="/admin/topics/new">
            <Button>
              <Plus className="mr-2 h-4 w-4" />
              Create Topic
            </Button>
          </Link>
        }
      />

      <div className="mb-4 flex items-center justify-between rounded-lg bg-muted p-4">
        <p className="text-sm text-muted-foreground">
          Topics are organized in a tree hierarchy. Click the arrows to expand/collapse sub-topics.
          Child topics automatically include parent topic when filtering.
        </p>
        <span className="text-sm font-medium text-muted-foreground">
          {totalTopics} top-level topic{totalTopics === 1 ? "" : "s"}
        </span>
      </div>

      <div className="rounded-md border">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Name</TableHead>
              <TableHead>Slug</TableHead>
              <TableHead>Parent</TableHead>
              <TableHead className="text-center">Level</TableHead>
              <TableHead className="text-right">Questions</TableHead>
              <TableHead className="text-right">Sub-topics</TableHead>
              <TableHead className="text-right">Used in Quizzes</TableHead>
              <TableHead className="text-right">Actions</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {topics.map((topic) => renderTopicRow(topic))}
            {topics.length === 0 && (
              <TableRow>
                <TableCell colSpan={8} className="py-8 text-center text-muted-foreground">
                  No topics found. Create your first topic to get started.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>

      <Dialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Delete Topic</DialogTitle>
            <div className="text-sm text-muted-foreground">
              Are you sure you want to delete &quot;{topicToDelete?.name}&quot;?

              {topicToDelete && (
                <div className="mt-4 space-y-2">
                  {topicToDelete._count.questions > 0 && (
                    <div className="font-medium text-destructive">
                      ⚠️ This topic has {topicToDelete._count.questions} question(s)
                    </div>
                  )}
                  {topicToDelete._count.children > 0 && (
                    <div className="font-medium text-destructive">
                      ⚠️ This topic has {topicToDelete._count.children} sub-topic(s)
                    </div>
                  )}
                  {topicToDelete._count.quizTopicConfigs > 0 && (
                    <div className="font-medium text-destructive">
                      ⚠️ This topic is used in {topicToDelete._count.quizTopicConfigs} quiz configuration(s)
                    </div>
                  )}
                  {(topicToDelete._count.questions > 0 ||
                    topicToDelete._count.children > 0 ||
                    topicToDelete._count.quizTopicConfigs > 0) && (
                      <p className="mt-2 text-sm">
                        You must remove/reassign all dependencies before deleting this topic.
                      </p>
                    )}
                </div>
              )}
            </div>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteDialogOpen(false)} disabled={deleting}>
              Cancel
            </Button>
            <Button variant="destructive" onClick={handleDelete} disabled={deleting}>
              {deleting ? "Deleting..." : "Delete Topic"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={mergeDialogOpen} onOpenChange={setMergeDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Merge Topic</DialogTitle>
            <div className="text-sm text-muted-foreground">
              Merge &quot;{topicToMerge?.name}&quot; into another topic.
              All questions, sub-topics, and stats will be moved.
            </div>
          </DialogHeader>

          <div className="py-4 space-y-4">
            <div className="space-y-2">
              <label className="text-sm font-medium">Destination Topic</label>
              <Popover open={comboboxOpen} onOpenChange={setComboboxOpen}>
                <PopoverTrigger asChild>
                  <Button
                    variant="outline"
                    role="combobox"
                    aria-expanded={comboboxOpen}
                    className="w-full justify-between"
                  >
                    {destinationTopicId
                      ? (() => {
                        const selected = topicToMerge && getMergeableTopics(topicToMerge.id).find((t) => t.id === destinationTopicId);
                        return selected ? `${selected.name} ${selected.level > 0 ? `(Level ${selected.level})` : "(Root)"}` : "Select destination topic...";
                      })()
                      : "Select destination topic..."}
                    <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-[400px] p-0">
                  <Command>
                    <CommandInput placeholder="Search topics..." />
                    <CommandList>
                      <CommandEmpty>No topic found.</CommandEmpty>
                      <CommandGroup>
                        {topicToMerge && getMergeableTopics(topicToMerge.id).map((t) => (
                          <CommandItem
                            key={t.id}
                            value={t.name}
                            onSelect={() => {
                              setDestinationTopicId(t.id);
                              setComboboxOpen(false);
                            }}
                          >
                            <Check
                              className={cn(
                                "mr-2 h-4 w-4",
                                destinationTopicId === t.id ? "opacity-100" : "opacity-0"
                              )}
                            />
                            {t.name} {t.level > 0 ? `(Level ${t.level})` : "(Root)"}
                          </CommandItem>
                        ))}
                      </CommandGroup>
                    </CommandList>
                  </Command>
                </PopoverContent>
              </Popover>
            </div>

            {topicToMerge && (
              <div className="rounded-md bg-muted p-3 text-sm space-y-1">
                <div className="font-medium mb-1 text-blue-600 dark:text-blue-400">Resources to be moved:</div>
                <div>• {topicToMerge._count.questions} Question(s)</div>
                <div>• {topicToMerge._count.children} Sub-topic(s)</div>
                <div>• {topicToMerge._count.quizTopicConfigs} Quiz Config(s)</div>
                <div className="mt-2 text-xs text-muted-foreground italic">
                  Note: The source topic &quot;{topicToMerge.name}&quot; will be deleted.
                </div>
              </div>
            )}
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setMergeDialogOpen(false)} disabled={merging}>
              Cancel
            </Button>
            <Button
              variant="default"
              className="bg-blue-600 hover:bg-blue-700"
              onClick={handleMerge}
              disabled={merging || !destinationTopicId}
            >
              {merging ? "Merging..." : "Confirm Merge"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/db";
import { requireAdmin } from "@/lib/auth-helpers";
import { questionsImportSchema } from "@/lib/validations/question.schema";
import { handleError, successResponse } from "@/lib/errors";
import { generateUniqueSlug } from "@/lib/services/slug.service";
import { Prisma, QuestionType, Difficulty } from "@prisma/client";

export const runtime = 'nodejs';
export const maxDuration = 60; // seconds

/**
 * Normalize difficulty values to uppercase for case-insensitive input
 */
function normalizeDifficulty(value: string | undefined): Difficulty {
    if (!value) return Difficulty.MEDIUM;
    const normalized = value.toUpperCase();
    if (['EASY', 'MEDIUM', 'HARD'].includes(normalized)) {
        return normalized as Difficulty;
    }
    return Difficulty.MEDIUM;
}

export async function POST(request: NextRequest) {
    try {
        await requireAdmin();

        const body = await request.json();

        // Pre-processing to normalize difficulties if they are strings
        const normalizedBody = Array.isArray(body)
            ? body.map((q: any) => ({
                ...q,
                difficulty: typeof q.difficulty === 'string' ? normalizeDifficulty(q.difficulty) : q.difficulty
            }))
            : body;

        // Validate the input
        const parseResult = questionsImportSchema.safeParse(normalizedBody);
        if (!parseResult.success) {
            return new Response(
                JSON.stringify({ error: "Invalid input", details: parseResult.error.format() }),
                { status: 400, headers: { "Content-Type": "application/json" } }
            );
        }

        const questionsData = parseResult.data;

        const result = await prisma.$transaction(async (tx) => {
            // Get default topic
            let defaultTopic = await tx.topic.findFirst({
                where: { slug: "general" },
            });

            if (!defaultTopic) {
                defaultTopic = await tx.topic.create({
                    data: {
                        name: "General",
                        slug: "general",
                        description: "General questions",
                        level: 0,
                    },
                });
            }

            // Resolve all topics
            const topicNames = new Set<string>();
            questionsData.forEach(q => {
                if (q.topic) topicNames.add(q.topic.trim());
            });

            const topicMap = new Map<string, string>(); // name -> id
            topicMap.set("General", defaultTopic.id);

            for (const name of topicNames) {
                if (name.toLowerCase() === "general") continue;

                let topic = await tx.topic.findFirst({
                    where: { name: { equals: name, mode: 'insensitive' } }
                });

                if (!topic) {
                    topic = await tx.topic.create({
                        data: {
                            name,
                            slug: await generateUniqueSlug(name, "topic"),
                            level: 0
                        }
                    });
                }
                topicMap.set(name, topic.id);
                topicMap.set(name.toLowerCase(), topic.id);
            }

            // Create questions in batches
            const BATCH_SIZE = 20;
            let importedCount = 0;

            for (let i = 0; i < questionsData.length; i += BATCH_SIZE) {
                const batch = questionsData.slice(i, i + BATCH_SIZE);

                await Promise.all(
                    batch.map(async (q) => {
                        const topicId = q.topic ? (topicMap.get(q.topic.trim()) || topicMap.get(q.topic.trim().toLowerCase()) || defaultTopic!.id) : defaultTopic!.id;

                        await tx.question.create({
                            data: {
                                questionText: q.text,
                                type: q.type as QuestionType,
                                difficulty: q.difficulty as Difficulty,
                                topicId,
                                hint: q.hint,
                                explanation: q.explanation,
                                answers: {
                                    create: q.answers.map((a, idx) => ({
                                        answerText: a.text,
                                        isCorrect: a.isCorrect,
                                        answerImageUrl: a.imageUrl,
                                        displayOrder: idx
                                    }))
                                }
                            }
                        });
                        importedCount++;
                    })
                );
            }

            return { importedCount };
        }, {
            maxWait: 30000,
            timeout: 60000,
        });

        return successResponse({
            message: `Successfully imported ${result.importedCount} questions.`,
            count: result.importedCount
        }, 201);

    } catch (error) {
        return handleError(error);
    }
}

import { NextRequest } from "next/server";
import { requireAdmin } from "@/lib/auth-helpers";
import { handleError, successResponse, BadRequestError, NotFoundError } from "@/lib/errors";
import { prisma } from "@/lib/db";
import { getSupabaseClient, isSupabaseConfigured, QUIZ_IMAGES_BUCKET } from "@/lib/supabase";
import { optimizeImage } from "@/lib/image-optimization";
import { GoogleGenerativeAI } from "@google/generative-ai";

// Use Node.js runtime for long-running AI operations
export const runtime = 'nodejs';

// Increase route timeout for AI image generation (can take 30-60 seconds)
export const maxDuration = 60; // seconds

const INSTRUCTION_MODEL = "gemini-2.5-flash";
const IMAGE_MODEL = "gemini-2.5-flash-image"; // Nano Banana
const MAX_SIZE_BYTES = 400 * 1024; // 400 KB
const TARGET_WIDTH = 1280;
const TARGET_HEIGHT = 720;

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    await requireAdmin();
    const { id } = await params;

    if (!process.env.GEMINI_API_KEY) {
      throw new BadRequestError("Gemini API key is not configured");
    }

    if (!isSupabaseConfigured()) {
      throw new BadRequestError("Supabase storage is not configured");
    }

    const quiz = await prisma.quiz.findUnique({
      where: { id },
      select: {
        id: true,
        title: true,
        description: true,
        topicConfigs: {
          select: {
            topic: {
              select: {
                name: true,
              },
            },
          },
        },
        questionPool: {
          select: {
            question: {
              select: {
                topic: {
                  select: { name: true }
                }
              },
            },
          },
          take: 5,
        },
      },
    });

    if (!quiz) {
      throw new NotFoundError("Quiz not found");
    }

    const topics = new Set<string>();
    quiz.topicConfigs.forEach((config) => {
      if (config.topic?.name) {
        topics.add(config.topic.name);
      }
    });
    quiz.questionPool.forEach((item) => {
      const topicName = item.question.topic?.name;
      if (topicName) {
        topics.add(topicName);
      }
    });

    const instructionPrompt = `You are an art director crafting prompts for image generators. Write a concise, vivid description (max 280 characters) for a sports quiz cover image with no text or logos.
Quiz title: ${quiz.title || "Untitled Sports Quiz"}
Quiz description: ${quiz.description || "(none)"}
Key topics: ${Array.from(topics).join(", ") || "general sports"}
Tone: energetic, competitive, modern broadcast graphics.
Mention relevant colors, action, and setting. Reply with description only.`;

    const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY);
    const model = genAI.getGenerativeModel({ model: INSTRUCTION_MODEL });

    const instructionResult = await model.generateContent(instructionPrompt);
    const generatedInstruction = instructionResult.response.text().trim();

    if (!generatedInstruction) {
      throw new BadRequestError("Prompt generation did not return any content");
    }

    // Generate Image using Gemini 2.5 Flash Image (Nano Banana)
    let imageBuffer: Buffer | null = null;
    let lastError: any = null;

    try {
      console.log(`Attempting image generation with ${IMAGE_MODEL} for prompt: ${generatedInstruction}...`);
      const imageModel = genAI.getGenerativeModel({ model: IMAGE_MODEL });

      const result = await imageModel.generateContent(generatedInstruction);
      const response = await result.response;

      // @ts-ignore - The SDK types might not strictly guarantee inlineData presence in all versions yet
      const parts = response.candidates?.[0]?.content?.parts;

      if (parts) {
        for (const part of parts) {
          if (part.inlineData && part.inlineData.data) {
            imageBuffer = Buffer.from(part.inlineData.data, 'base64');
            break;
          }
        }
      }

      if (!imageBuffer) {
        // Fallback/Check for refusal or other issues
        console.warn("No inline data found in response:", JSON.stringify(response, null, 2));
        throw new Error("Model generated a response but no image data was found.");
      }

    } catch (error: any) {
      console.error(`${IMAGE_MODEL} failed:`, error);
      lastError = error;

      // Improve error message for known issues
      if (error.message?.includes("429") || error.message?.includes("quota")) {
        throw new BadRequestError(`Gemini Image API Quota Exceeded: ${error.message} (Please check your Google AI Studio billing/quota settings for ${IMAGE_MODEL})`);
      }

      throw new BadRequestError(
        `Gemini Image API error: ${error.message}`
      );
    }

    if (!imageBuffer) {
      throw new BadRequestError("Failed to generate image buffer");
    }

    const optimized = await optimizeImage(imageBuffer, {
      width: TARGET_WIDTH,
      height: TARGET_HEIGHT,
      fit: 'cover',
      maxSizeBytes: MAX_SIZE_BYTES
    });

    const supabase = getSupabaseClient();
    const filePath = `quizzes/${id}/ai-cover-${Date.now()}.webp`;

    // Upload with retry logic for reliability
    let uploadAttempts = 0;
    let uploadError: any = null;
    const MAX_UPLOAD_RETRIES = 3;

    while (uploadAttempts < MAX_UPLOAD_RETRIES) {
      const { error } = await supabase.storage
        .from(QUIZ_IMAGES_BUCKET)
        .upload(filePath, optimized, {
          contentType: "image/webp",
          upsert: true,
        });

      if (!error) {
        uploadError = null;
        break;
      }

      uploadError = error;
      uploadAttempts++;

      if (uploadAttempts < MAX_UPLOAD_RETRIES) {
        // Wait before retry (exponential backoff)
        await new Promise(resolve => setTimeout(resolve, 1000 * uploadAttempts));
      }
    }

    if (uploadError) {
      console.error("Supabase upload error:", uploadError);
      throw new BadRequestError(
        uploadError.message || "Failed to upload image to storage after multiple attempts"
      );
    }

    const { data: publicUrlData } = supabase.storage
      .from(QUIZ_IMAGES_BUCKET)
      .getPublicUrl(filePath);

    const imageUrl = publicUrlData?.publicUrl;

    if (!imageUrl) {
      throw new BadRequestError("Unable to retrieve public URL for uploaded image");
    }

    await prisma.quiz.update({
      where: { id },
      data: {
        descriptionImageUrl: imageUrl,
      },
    });

    return successResponse({ url: imageUrl });
  } catch (error) {
    return handleError(error);
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/db";
import { requireAdmin } from "@/lib/auth-helpers";
import { questionsImportSchema } from "@/lib/validations/quiz.schema";
import { handleError, successResponse, NotFoundError, BadRequestError } from "@/lib/errors";
import { generateUniqueSlug } from "@/lib/services/slug.service";
import { Prisma, Difficulty, QuestionType } from "@prisma/client";
import { syncTopicsFromQuestionPool } from "@/lib/services/quiz-topic-sync.service";

export const runtime = 'nodejs';
export const maxDuration = 60; // seconds

// POST /api/admin/quizzes/[id]/import - Import questions into an existing quiz
export async function POST(
    request: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const { id: quizId } = await params;
        await requireAdmin();

        const body = await request.json();
        console.log('DEBUG: Import Route Body:', JSON.stringify(body, null, 2));

        // Validate the input - difficulty normalization happens in the schema
        const validationResult = questionsImportSchema.safeParse(body);
        if (!validationResult.success) {
            console.error('DEBUG: Import Route Validation Failed:', JSON.stringify(validationResult.error, null, 2));
            throw validationResult.error;
        }
        const { questions } = validationResult.data;

        // Check if quiz exists
        const existingQuiz = await prisma.quiz.findUnique({
            where: { id: quizId },
            include: {
                _count: {
                    select: { questionPool: true }
                }
            }
        });

        if (!existingQuiz) {
            throw new NotFoundError("Quiz not found");
        }

        // Start transaction
        const result = await prisma.$transaction(async (tx) => {
            // Get default topic
            let defaultTopic = await tx.topic.findFirst({
                where: { slug: "general" },
            });

            if (!defaultTopic) {
                defaultTopic = await tx.topic.create({
                    data: {
                        name: "General",
                        slug: "general",
                        description: "General questions",
                        level: 0,
                    },
                });
            }

            // Resolve topics
            const topicUsageMap = new Map<string, string>(); // normalized name -> original name
            const normalizeTopicName = (name: string) => name.trim().toLowerCase();

            for (const q of questions) {
                const topicName = q.topic?.trim() || "General";
                topicUsageMap.set(normalizeTopicName(topicName), topicName);
            }

            const topicNameMap = new Map<string, string>(); // normalized name -> topicId
            const normalizedNames = Array.from(topicUsageMap.keys());

            // Fetch existing topics
            const existingTopics = await tx.topic.findMany({
                where: {
                    OR: normalizedNames.map((normalized) => ({
                        name: {
                            equals: topicUsageMap.get(normalized)!,
                            mode: "insensitive" as const,
                        },
                    })),
                },
            });

            for (const topic of existingTopics) {
                topicNameMap.set(normalizeTopicName(topic.name), topic.id);
            }

            // Create missing topics
            for (const normalizedName of normalizedNames) {
                if (topicNameMap.has(normalizedName)) continue;

                const topicName = topicUsageMap.get(normalizedName)!;
                const slug = await generateUniqueSlug(topicName, "topic");
                const newTopic = await tx.topic.create({
                    data: {
                        name: topicName,
                        slug,
                        level: 0,
                    },
                });
                topicNameMap.set(normalizedName, newTopic.id);
            }

            // Create questions and pool entries
            const BATCH_SIZE = 20;
            let createdCount = 0;
            const currentPoolCount = existingQuiz._count.questionPool;

            for (let i = 0; i < questions.length; i += BATCH_SIZE) {
                const batch = questions.slice(i, i + BATCH_SIZE);
                await Promise.all(
                    batch.map(async (qData, idx) => {
                        const topicId = topicNameMap.get(normalizeTopicName(qData.topic || "General")) || defaultTopic!.id;

                        const question = await tx.question.create({
                            data: {
                                questionText: qData.text,
                                type: (qData.type?.toUpperCase() || "MULTIPLE_CHOICE") as QuestionType,
                                difficulty: qData.difficulty as Difficulty,
                                topicId,
                                hint: qData.hint,
                                explanation: qData.explanation,
                                answers: {
                                    create: qData.answers.map((a, aIdx) => ({
                                        answerText: a.text,
                                        isCorrect: a.isCorrect,
                                        answerImageUrl: a.imageUrl,
                                        displayOrder: aIdx,
                                    })),
                                },
                            },
                        });

                        const order = qData.order ?? (currentPoolCount + i + idx + 1);

                        await tx.quizQuestionPool.create({
                            data: {
                                quizId: quizId,
                                questionId: question.id,
                                order,
                                points: 1,
                            },
                        });

                        createdCount++;
                    })
                );
            }

            return { count: createdCount };
        }, {
            maxWait: 30000,
            timeout: 60000,
        });

        // Sync topic configurations after transaction completes
        await syncTopicsFromQuestionPool(quizId);

        return successResponse({
            message: `Successfully imported ${result.count} questions into the quiz.`,
            importedCount: result.count,
        }, 201);

    } catch (error) {
        return handleError(error);
    }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/db";
import { requireAdmin } from "@/lib/auth-helpers";
import { quizImportSchema, type QuizImportInput, type QuizImportQuestion } from "@/lib/validations/quiz.schema";
import { handleError, successResponse, BadRequestError } from "@/lib/errors";
import { generateUniqueSlug } from "@/lib/services/slug.service";
import { Prisma, Difficulty, QuestionType } from "@prisma/client";

// Use Node.js runtime for long-running import operations
export const runtime = 'nodejs';

// Increase route timeout for large quiz imports (100+ questions can take 30-60 seconds)
export const maxDuration = 60; // seconds

/**
 * Normalize difficulty values to uppercase for case-insensitive input
 */

/**
 * Normalize difficulty values to uppercase for case-insensitive input
 */
function normalizeDifficulty(value: string | undefined): string | undefined {
  if (!value) return undefined;
  const normalized = value.toUpperCase();
  // Validate it's a valid difficulty
  if (['EASY', 'MEDIUM', 'HARD'].includes(normalized)) {
    return normalized;
  }
  return value; // Return original if invalid, let schema validation handle the error
}

// POST /api/admin/quizzes/import - Bulk import quiz from JSON
export async function POST(request: NextRequest) {
  try {
    await requireAdmin();

    const body = await request.json();

    // Normalize difficulty values to uppercase (case-insensitive input)
    if (body.difficulty) {
      body.difficulty = normalizeDifficulty(body.difficulty);
    }
    if (Array.isArray(body.questions)) {
      body.questions = body.questions.map((q: any) => ({
        ...q,
        difficulty: normalizeDifficulty(q.difficulty)
      }));
    }

    // Validate the input
    const parseResult = quizImportSchema.safeParse(body);
    if (!parseResult.success) {
      return new Response(
        JSON.stringify({ error: "Invalid input", details: parseResult.error.format() }),
        { status: 400, headers: { "Content-Type": "application/json" } }
      );
    }

    // Extract validated data with type assertion
    const validatedData = parseResult.data as QuizImportInput;
    const {
      title,
      slug: providedSlug,
      description,
      sport,
      difficulty,
      duration,
      timePerQuestion,
      maxAttemptsPerUser,
      showHints,
      randomizeQuestionOrder,
      completionBonus,
      passingScore,
      seo,
      playMode,
      playConfig
    } = validatedData;

    // Determine questions: if Grid mode, auto-generate them
    let questions: QuizImportQuestion[] = validatedData.questions || [];

    if (playMode === "GRID_3X3" && playConfig) {
      questions = [];
      const { rows, cols, cells } = playConfig as any; // Cast to any to bypass strict checks if types are stale

      // Generate 9 questions from grid
      for (let r = 0; r < 3; r++) {
        for (let c = 0; c < 3; c++) {
          const rowLabel = rows[r];
          const colLabel = cols[c];

          // Get accepted answers for this cell (split by newline if string, or use array)
          const cellContent = cells[r][c];
          let acceptedAnswers: string[] = [];

          if (Array.isArray(cellContent)) {
            acceptedAnswers = cellContent;
          } else if (typeof cellContent === 'string') {
            acceptedAnswers = (cellContent as string).split('\n').map((s: string) => s.trim()).filter(Boolean);
          }

          if (acceptedAnswers.length === 0) {
            throw new BadRequestError(`Grid cell [${r},${c}] has no accepted answers`);
          }

          questions.push({
            text: `Row: ${rowLabel}, Col: ${colLabel}`,
            type: "FILL_BLANK",
            difficulty: difficulty,
            topic: "Grid Cell", // Internal topic
            order: r * 3 + c,
            answers: acceptedAnswers.map(ans => ({
              text: ans,
              isCorrect: true // All provided answers are correct for this cell
            }))
          });
        }
      }
    }

    // Calculate completion bonus if not provided
    const finalCompletionBonus = completionBonus ?? (questions.length * 100);

    // Generate unique slug
    const slug = providedSlug
      ? await generateUniqueSlug(providedSlug, "quiz")
      : await generateUniqueSlug(title, "quiz");

    // Create quiz and questions in a transaction with extended timeout for large imports
    const quiz = await prisma.$transaction(async (tx: Prisma.TransactionClient) => {
      // Get or create default topic if needed
      let defaultTopic = await tx.topic.findFirst({
        where: { slug: "general" },
      });

      if (!defaultTopic) {
        defaultTopic = await tx.topic.create({
          data: {
            name: "General",
            slug: "general",
            description: "General questions",
            level: 0,
          },
        });
      }

      // Collect topic usage and determine primary sport
      const topicUsageMap = new Map<string, { count: number; configs: Set<string> }>();

      const normalizeTopicName = (name: string) => name.trim().toLowerCase();
      const topicOriginalNameMap = new Map<string, string>();

      for (const q of questions) {
        const topicName = q.topic?.trim() || "General";
        const normalized = normalizeTopicName(topicName);
        if (!topicOriginalNameMap.has(normalized)) {
          topicOriginalNameMap.set(normalized, topicName);
        }

        const usage = topicUsageMap.get(normalized) || { count: 0, configs: new Set<string>() };
        usage.count++;
        usage.configs.add(q.difficulty);
        topicUsageMap.set(normalized, usage);
      }

      // Resolve all topics at once
      const topicNameMap = new Map<string, { id: string; name: string }>();
      const normalizedNames = Array.from(topicOriginalNameMap.keys());

      if (normalizedNames.length > 0) {

        const existingTopics = await tx.topic.findMany({
          where: {
            OR: normalizedNames.map((normalized) => ({
              name: {
                equals: topicOriginalNameMap.get(normalized)!,
                mode: "insensitive" as const,
              },
            })),
          },
          select: { id: true, name: true },
        });

        for (const topic of existingTopics) {
          topicNameMap.set(normalizeTopicName(topic.name), { id: topic.id, name: topic.name });
        }

        for (const normalizedName of normalizedNames) {
          if (topicNameMap.has(normalizedName)) continue;

          const topicName = topicOriginalNameMap.get(normalizedName)!;
          // Use upsert to handle race conditions where topic might be created by another process
          // generateUniqueSlug might be slightly wasteful if topic exists but safe
          const slug = await generateUniqueSlug(topicName, "topic");

          const topic = await tx.topic.upsert({
            where: { name: topicName },
            update: {},
            create: {
              name: topicName,
              slug,
              level: 0,
            },
          });
          topicNameMap.set(normalizedName, { id: topic.id, name: topic.name });
        }
      }

      // Determine the most frequent topic to use for Sport auto-detection (if Sport not provided)
      let primaryTopicName = "General";
      let maxCount = -1;
      for (const [name, usage] of topicUsageMap.entries()) {
        if (usage.count > maxCount) {
          maxCount = usage.count;
          primaryTopicName = topicOriginalNameMap.get(name) || "General";
        }
      }

      // Resolve sport to a canonical Level 0 Topic (root topic)
      let canonicalSportName: string | undefined = undefined;
      const sportToResolve = (sport && sport.trim().length > 0) ? sport.trim() : primaryTopicName;

      if (sportToResolve) {
        // Try to find existing root topic first
        const existingRoot = await tx.topic.findFirst({
          where: {
            parentId: null,
            name: { equals: sportToResolve, mode: "insensitive" },
          },
          select: { id: true, name: true },
        });

        if (existingRoot) {
          canonicalSportName = existingRoot.name; // preserve canonical casing
        } else {
          // Use upsert for safety against race conditions
          const slug = await generateUniqueSlug(sportToResolve, "topic");
          const rootTopic = await tx.topic.upsert({
            where: { name: sportToResolve },
            update: {}, // exists, do nothing
            create: {
              name: sportToResolve,
              slug,
              level: 0,
            },
            select: { name: true }
          });
          canonicalSportName = rootTopic.name;
        }
      }

      // Create the quiz
      const newQuiz = await tx.quiz.create({
        data: {
          title,
          slug,
          description,
          sport: canonicalSportName,
          difficulty,
          duration,
          timePerQuestion,
          maxAttemptsPerUser,
          showHints,
          randomizeQuestionOrder,
          completionBonus: finalCompletionBonus,
          passingScore,
          seoTitle: seo?.title,
          seoDescription: seo?.description,
          seoKeywords: seo?.keywords || [],
          questionSelectionMode: "FIXED",
          status: "DRAFT",
          playMode: playMode || "STANDARD",
          playConfig: playConfig as any, // Prisma Json handling
        } as any,
      });

      // Create Topic Configurations automatically
      // ... (existing logic for topic configs)
      const topicConfigsToCreate = [];
      for (const [normalizedName, usage] of topicUsageMap.entries()) {
        const topicId = topicNameMap.get(normalizedName)?.id;
        if (!topicId) continue;

        // Count questions per difficulty for this topic
        const difficultyCounts = new Map<string, number>();
        for (const q of questions) {
          const qTopic = normalizeTopicName(q.topic || "General");
          if (qTopic === normalizedName) {
            const d = q.difficulty;
            difficultyCounts.set(d, (difficultyCounts.get(d) || 0) + 1);
          }
        }

        for (const [diff, count] of difficultyCounts.entries()) {
          topicConfigsToCreate.push({
            quizId: newQuiz.id,
            topicId,
            difficulty: diff as Difficulty,
            questionCount: count,
          });
        }
      }

      if (topicConfigsToCreate.length > 0) {
        await tx.quizTopicConfig.createMany({
          data: topicConfigsToCreate,
        });
      }

      // Create all questions in batches to avoid overwhelming the database
      const BATCH_SIZE = 20;
      const createdQuestions = [];

      for (let i = 0; i < questions.length; i += BATCH_SIZE) {
        const batch = questions.slice(i, i + BATCH_SIZE);
        const batchResults = await Promise.all(
          batch.map((questionData) => {
            const questionType = (questionData.type
              ? questionData.type.toUpperCase()
              : "MULTIPLE_CHOICE") as QuestionType;

            const normalizedTopicName = normalizeTopicName(questionData.topic || "General");
            const topicId = topicNameMap.get(normalizedTopicName)?.id || defaultTopic!.id;

            return tx.question.create({
              data: {
                type: questionType,
                topicId,
                difficulty: questionData.difficulty,
                questionText: questionData.text,
                hint: questionData.hint,
                explanation: questionData.explanation,
                answers: {
                  create: questionData.answers.map((answer, idx) => ({
                    answerText: answer.text,
                    answerImageUrl: answer.imageUrl,
                    isCorrect: answer.isCorrect,
                    displayOrder: idx,
                  })),
                },
              },
            });
          })
        );
        createdQuestions.push(...batchResults);
      }

      // Create quiz question pool entries in batch
      const poolEntries = createdQuestions.map((question, i) => ({
        quizId: newQuiz.id,
        questionId: question.id,
        order: questions[i].order !== undefined ? questions[i].order : i + 1, // Respect 0-based indexing for Grid if provided
        points: 1,
      }));

      // Validate unique order values
      const orderValues = poolEntries.map(e => e.order).filter(o => o !== null);
      const uniqueOrders = new Set(orderValues);
      if (orderValues.length !== uniqueOrders.size) {
        throw new BadRequestError("Duplicate order values detected in question pool.");
      }

      await tx.quizQuestionPool.createMany({
        data: poolEntries as any, // Cast to any to avoid strict type checks if order is optional in schema but required in DB
      });

      // Return the complete quiz with questions
      return await tx.quiz.findUnique({
        where: { id: newQuiz.id },
        include: {
          questionPool: {
            include: {
              question: {
                include: {
                  answers: true,
                },
              },
            },
            orderBy: { order: "asc" },
          },
          topicConfigs: {
            include: {
              topic: true
            }
          },
          _count: {
            select: {
              questionPool: true,
            },
          },
        },
      });
    }, {
      maxWait: 30000, // Maximum wait time to acquire a transaction (30 seconds)
      timeout: 60000,  // Maximum time the transaction can run (60 seconds)
    });

    return successResponse(
      {
        quiz,
        message: "Quiz imported successfully with automatically derived topic configurations",
      },
      201
    );
  } catch (error) {
    return handleError(error);
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/db";
import { requireAdmin } from "@/lib/auth-helpers";
import { handleError, successResponse, BadRequestError, NotFoundError } from "@/lib/errors";
import { z } from "zod";
import { getAIModel, getAIQuizPrompt } from "@/lib/services/settings.service";
import {
  createBackgroundTask,
  markBackgroundTaskCompleted,
  markBackgroundTaskFailed,
  markBackgroundTaskInProgress,
  updateBackgroundTask,
} from "@/lib/services/background-task.service";
import { BackgroundTaskType } from "@prisma/client";
import {
  callOpenAIWithRetry,
  extractContentFromCompletion,
  extractUsageStats,
} from "@/lib/services/ai-openai-client.service";
import { processAIQuestionsTask } from "@/lib/services/ai-questions-processor.service";
import { after } from "next/server";

// Use Node.js runtime for long-running AI operations
export const runtime = 'nodejs';

// Increase route timeout for AI generation
export const maxDuration = 60;

const generationSchema = z
  .object({
    easyCount: z.number().int().min(0).max(50).default(0),
    mediumCount: z.number().int().min(0).max(50).default(0),
    hardCount: z.number().int().min(0).max(50).default(0),
  })
  .refine((v) => (v.easyCount + v.mediumCount + v.hardCount) > 0, {
    message: "Provide at least one question to generate",
    path: ["easyCount"],
  });

export async function POST(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  let taskId: string | null = null;
  try {
    const admin = await requireAdmin();

    if (!process.env.OPENAI_API_KEY) {
      throw new BadRequestError("OpenAI API key is not configured. Please add OPENAI_API_KEY to your environment variables.");
    }

    const { id } = await params;

    const body = await request.json();
    const { easyCount, mediumCount, hardCount } = generationSchema.parse(body);

    const topic = await prisma.topic.findUnique({ where: { id } });
    if (!topic) {
      throw new NotFoundError("Topic not found");
    }

    const total = easyCount + mediumCount + hardCount;
    const aiModel = await getAIModel();
    const baseTemplate = await getAIQuizPrompt();

    const backgroundTask = await createBackgroundTask({
      userId: admin.id,
      type: BackgroundTaskType.AI_TOPIC_QUESTION_GENERATION,
      label: `AI Questions • ${topic.name}`,
      input: {
        topicId: id,
        topicName: topic.name,
        easyCount,
        mediumCount,
        hardCount,
        total,
        model: aiModel,
      },
    });
    taskId = backgroundTask.id;

    // Start processing in background without Inngest
    const finalTaskId = taskId;
    after(() => processAIQuestionsTask(finalTaskId));

    return successResponse({
      taskId,
      status: "processing",
      message: "Question generation started via Inngest.",
    });
  } catch (error) {
    if (taskId) {
      const message = error instanceof Error ? error.message : "Unknown error";
      try {
        await markBackgroundTaskFailed(taskId, message);
      } catch {
        // Silently handle task status update errors
      }
    }
    return handleError(error);
  }
}

