"use client";

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { getDuplicateGroups, resolveDuplicateGroup, type DuplicateGroup } from "@/app/actions/admin-questions"; // You'll need to export DuplicateGroup
import { useToast } from "@/hooks/use-toast";
import { Loader2, AlertTriangle, Check, Trash2, GitMerge } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

interface DuplicateResolutionModalProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
}

export function DuplicateResolutionModal({ open, onOpenChange }: DuplicateResolutionModalProps) {
    const { toast } = useToast();
    const [isLoading, setIsLoading] = useState(false);
    const [groups, setGroups] = useState<DuplicateGroup[]>([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [resolving, setResolving] = useState(false);

    useEffect(() => {
        if (open) {
            const loadDuplicates = async () => {
                setIsLoading(true);
                try {
                    const data = await getDuplicateGroups();
                    setGroups(data);
                } catch (error) {
                    toast({
                        title: "Error",
                        description: "Failed to load duplicates.",
                        variant: "destructive",
                    });
                    onOpenChange(false);
                } finally {
                    setIsLoading(false);
                }
            };
            loadDuplicates();
        } else {
            setGroups([]);
            setCurrentIndex(0);
        }
    }, [open, onOpenChange, toast]);

    const handleResolve = async (keepId: string) => {
        setResolving(true);
        const currentGroup = groups[currentIndex];
        const removeIds = currentGroup.questions.filter(q => q.id !== keepId).map(q => q.id);

        try {
            const result = await resolveDuplicateGroup(keepId, removeIds);
            if (result.success) {
                toast({
                    title: "Resolved",
                    description: "Duplicates merged successfully.",
                });

                // Remove processed group
                setGroups(prev => prev.filter((_, i) => i !== currentIndex));
                // Index stays same (so next item moves into view), unless we were at end
                if (currentIndex >= groups.length - 1) {
                    setCurrentIndex(Math.max(0, groups.length - 2));
                }
            } else {
                toast({
                    title: "Failed",
                    description: result.error,
                    variant: "destructive",
                });
            }
        } catch (error) {
            toast({
                title: "Error",
                description: "Failed to resolve duplicates.",
                variant: "destructive",
            });
        } finally {
            setResolving(false);
        }
    };

    const handleAutoResolve = async () => {
        // Automatically keep the oldest (first one usually, based on sort order in query)
        // Assuming groups[currentIndex].questions is sorted by createdAt or we sort it here
        const currentGroup = groups[currentIndex];
        const sorted = [...currentGroup.questions].sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
        const keepId = sorted[0].id; // Keep oldest
        await handleResolve(keepId);
    };

    if (isLoading) {
        return (
            <Dialog open={open} onOpenChange={onOpenChange}>
                <DialogContent>
                    <div className="flex flex-col items-center justify-center py-10 space-y-4">
                        <Loader2 className="h-8 w-8 animate-spin text-primary" />
                        <p className="text-sm text-muted-foreground">Scanning for duplicates...</p>
                    </div>
                </DialogContent>
            </Dialog>
        );
    }

    if (groups.length === 0) {
        // Can show brief success message before closing or just text
        return (
            <Dialog open={open} onOpenChange={onOpenChange}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Cleanup Complete</DialogTitle>
                        <DialogDescription>No duplicates found in the database.</DialogDescription>
                    </DialogHeader>
                    <DialogFooter>
                        <Button onClick={() => onOpenChange(false)}>Close</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        );
    }

    const currentGroup = groups[currentIndex];

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-2xl">
                <DialogHeader>
                    <DialogTitle className="flex items-center justify-between">
                        <span>Resolve Duplicates ({groups.length} remaining)</span>
                        {currentGroup?.hasTopicConflict && (
                            <Badge variant="destructive" className="ml-2">Topic Conflict</Badge>
                        )}
                    </DialogTitle>
                    <DialogDescription>
                        Review duplicate questions and choose which one to keep.
                    </DialogDescription>
                </DialogHeader>

                {currentGroup && (
                    <div className="space-y-6">
                        <div className="p-4 bg-muted/50 rounded-lg border">
                            <h3 className="font-semibold mb-1">Question Text</h3>
                            <p className="text-lg">{currentGroup.text}</p>
                        </div>

                        <div className="grid gap-4">
                            {currentGroup.questions.map((q) => (
                                <div key={q.id} className={cn(
                                    "flex items-center justify-between p-4 rounded-lg border transition-all",
                                    "hover:bg-muted/50"
                                )}>
                                    <div className="space-y-1">
                                        <div className="flex items-center gap-2">
                                            <Badge variant="outline">{q.topicName}</Badge>
                                            <span className="text-xs text-muted-foreground">
                                                Created {new Date(q.createdAt).toLocaleDateString()}
                                            </span>
                                        </div>
                                        <div className="text-xs text-muted-foreground flex gap-3">
                                            <span>{q.usageCount.userAnswers} answers</span>
                                            <span>{q.usageCount.quizPools} quizzes</span>
                                            <span className="font-mono text-[10px] opacity-50">{q.id}</span>
                                        </div>
                                    </div>
                                    <Button
                                        size="sm"
                                        onClick={() => handleResolve(q.id)}
                                        disabled={resolving}
                                        variant={currentGroup.hasTopicConflict ? "default" : "secondary"}
                                        className="gap-2"
                                    >
                                        {resolving ? <Loader2 className="h-3 w-3 animate-spin" /> : <Check className="h-3 w-3" />}
                                        Keep This
                                    </Button>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                <DialogFooter className="sm:justify-between">
                    <Button variant="ghost" onClick={() => onOpenChange(false)}>
                        Cancel
                    </Button>
                    {!currentGroup?.hasTopicConflict && (
                        <Button
                            variant="outline"
                            onClick={handleAutoResolve}
                            disabled={resolving}
                            className="text-muted-foreground"
                        >
                            Auto-resolve (Keep Oldest)
                        </Button>
                    )}
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Loader2, Search, Trophy, ArrowRight, Target } from "lucide-react";
import { searchQuizzes, createChallenge } from "@/app/actions/challenge-actions";
import { useDebounce } from "@/hooks/use-debounce";
import { useToast } from "@/hooks/use-toast";
import { Badge } from "@/components/ui/badge";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

interface CreateChallengeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  preselectedQuizId?: string;
  preselectedFriendId?: string;
}

interface Quiz {
  id: string;
  title: string;
  sport: string | null;
  difficulty: "EASY" | "MEDIUM" | "HARD";
  description: string | null;
  questionCount: number | null;
}

export function CreateChallengeModal({
  isOpen,
  onClose,
  onSuccess,
  preselectedFriendId
}: CreateChallengeModalProps) {
  const [search, setSearch] = useState("");
  const [quizzes, setQuizzes] = useState<Quiz[]>([]);
  const [loading, setLoading] = useState(false);
  const [sending, setSending] = useState<string | null>(null);
  const debouncedSearch = useDebounce(search, 500);
  const { toast } = useToast();

  useEffect(() => {
    if (isOpen) {
      setSearch("");
      setQuizzes([]);
      handleSearch("");
    }
  }, [isOpen]);

  useEffect(() => {
    handleSearch(debouncedSearch);
  }, [debouncedSearch]);

  const handleSearch = async (query: string) => {
    setLoading(true);
    try {
      const results = await searchQuizzes(query);
      setQuizzes(results);
    } catch (error) {
      console.error("Failed to search quizzes", error);
    } finally {
      setLoading(false);
    }
  };

  const handleChallenge = async (quiz: Quiz) => {
    if (!preselectedFriendId) return;

    setSending(quiz.id);
    try {
      const result = await createChallenge(preselectedFriendId, quiz.id);
      if (result.error) {
        toast({
          title: "Error",
          description: result.error,
          variant: "destructive",
        });
      } else {
        toast({
          title: "Challenge Sent!",
          description: `Challenge sent for ${quiz.title}.`,
        });
        onSuccess();
        onClose();
      }
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to send challenge",
        variant: "destructive",
      });
    } finally {
      setSending(null);
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-2xl bg-background border border-border shadow-2xl p-0 overflow-hidden sm:rounded-2xl gap-0 max-h-[90vh] flex flex-col">

        <DialogHeader className="p-6 pb-6 border-b border-border bg-muted/10 shrink-0">
          <div className="flex items-center justify-between">
            <div className="space-y-1">
              <DialogTitle className="text-2xl font-black uppercase tracking-tight text-foreground">
                Initiate Challenge
              </DialogTitle>
              <DialogDescription className="text-xs font-bold uppercase tracking-widest text-muted-foreground/80">
                Select a tactical scenario for your opponent
              </DialogDescription>
            </div>
            <div className="h-10 w-10 rounded-xl bg-primary/5 border border-primary/10 flex items-center justify-center text-primary shadow-sm hidden sm:flex">
              <Trophy className="h-5 w-5" />
            </div>
          </div>
        </DialogHeader>

        <div className="p-6 bg-background space-y-6 flex-1 overflow-hidden flex flex-col">
          <div className="relative shrink-0">
            <Search className="absolute left-4 top-1/2 h-5 w-5 -translate-y-1/2 text-muted-foreground transition-colors" />
            <Input
              placeholder="SEARCH OPERATIONS DATABASE..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-12 bg-muted/30 border-input h-14 text-base font-medium focus-visible:ring-2 focus-visible:ring-primary/20 focus-visible:border-primary transition-all placeholder:text-muted-foreground/50 placeholder:uppercase placeholder:text-sm placeholder:tracking-wider placeholder:font-bold rounded-xl"
            />
          </div>

          <div className="-mr-2 pr-2 overflow-y-auto flex-1 custom-scrollbar">
            <AnimatePresence mode="wait">
              {loading && quizzes.length === 0 ? (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="flex flex-col items-center justify-center py-12 space-y-3"
                >
                  <Loader2 className="h-8 w-8 animate-spin text-primary/40" />
                  <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest animate-pulse">Accessing Archives...</p>
                </motion.div>
              ) : quizzes.length > 0 ? (
                <div className="grid gap-3 pb-2">
                  {quizzes.map((quiz, index) => (
                    <motion.div
                      key={quiz.id}
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: index * 0.03, duration: 0.25 }}
                      className="group relative flex items-center justify-between p-4 rounded-xl border border-border bg-card hover:bg-muted/30 hover:border-primary/30 transition-all duration-200 cursor-pointer"
                      onClick={() => handleChallenge(quiz)}
                    >
                      <div className="space-y-2 mr-6 shrink min-w-0">
                        <div className="flex items-center gap-2 mb-1">
                          <Badge
                            variant="outline"
                            className={cn(
                              "text-[10px] h-5 px-1.5 rounded-md border text-center font-bold tracking-wider uppercase",
                              quiz.difficulty === 'HARD' ? "bg-red-500/5 text-red-600 border-red-200 dark:border-red-900/30" :
                                quiz.difficulty === 'MEDIUM' ? "bg-amber-500/5 text-amber-600 border-amber-200 dark:border-amber-900/30" :
                                  "bg-emerald-500/5 text-emerald-600 border-emerald-200 dark:border-emerald-900/30"
                            )}
                          >
                            {quiz.difficulty}
                          </Badge>
                          {quiz.sport && (
                            <div className="flex items-center gap-1.5 text-[10px] font-bold text-muted-foreground uppercase tracking-wider opacity-70">
                              <span className="w-1 h-1 rounded-full bg-muted-foreground/50" />
                              <Target className="h-3 w-3" />
                              {quiz.sport}
                            </div>
                          )}
                        </div>
                        <h4 className="font-black text-lg text-foreground group-hover:text-primary transition-colors uppercase tracking-tight leading-6 line-clamp-2">
                          {quiz.title}
                        </h4>
                      </div>

                      <div className="shrink-0">
                        <Button
                          size="icon"
                          disabled={sending === quiz.id}
                          className={cn(
                            "rounded-full h-10 w-10 transition-all duration-300",
                            sending === quiz.id
                              ? "bg-background border border-border text-muted-foreground"
                              : "bg-primary text-primary-foreground group-hover:scale-105 shadow-md group-hover:shadow-primary/20"
                          )}
                        >
                          {sending === quiz.id ? (
                            <Loader2 className="h-4 w-4 animate-spin" />
                          ) : (
                            <ArrowRight className="h-5 w-5" />
                          )}
                        </Button>
                      </div>

                      {/* Full card click effect */}
                      <span className="absolute inset-0 rounded-xl ring-2 ring-primary/20 ring-offset-2 ring-offset-background opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />
                    </motion.div>
                  ))}
                </div>
              ) : (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="flex flex-col items-center justify-center py-20 space-y-4 text-center opacity-60"
                >
                  <div className="h-16 w-16 rounded-full bg-muted/50 border border-border flex items-center justify-center">
                    <Search className="h-8 w-8 text-muted-foreground/60" />
                  </div>
                  <div className="space-y-1">
                    <p className="text-sm font-black uppercase tracking-widest text-muted-foreground">No matches found</p>
                    <p className="text-[10px] text-muted-foreground/60 font-medium max-w-[200px] mx-auto">Try adjusting your search criteria</p>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, Trophy, Medal, User, Flag, Calendar, Hash, X } from 'lucide-react';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { DailyGameResult } from './DailyGameResult';
import { useToast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';
import type { DailyGameType } from '@/lib/utils/daily-game-logic';

interface AthleteGuessGameProps {
    gameId: string;
    maxGuesses: number;
    clues?: Record<string, unknown>;
    initialGuesses?: string[];
    isCompleted?: boolean;
    targetValue?: string;
    gameNumber: number;
    gameType: DailyGameType;
}

interface GuessResult {
    name: string;
    isCorrect: boolean;
}

export function AthleteGuessGame({
    gameId,
    maxGuesses,
    clues,
    initialGuesses = [],
    isCompleted = false,
    targetValue,
    gameNumber,
    gameType,
}: AthleteGuessGameProps) {
    const [guesses, setGuesses] = useState<GuessResult[]>([]);
    const [searchQuery, setSearchQuery] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [gameOver, setGameOver] = useState(isCompleted);
    const [won, setWon] = useState(false);
    const [showResult, setShowResult] = useState(false);
    const [solution, setSolution] = useState(targetValue);
    const { toast } = useToast();

    const handleSubmit = async () => {
        if (!searchQuery.trim() || isSubmitting) return;

        setIsSubmitting(true);

        try {
            const response = await fetch('/api/daily/guess', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ gameId, guess: searchQuery }),
            });

            const data = await response.json();

            if (!response.ok) {
                throw new Error(data.error || 'Failed to submit guess');
            }

            const newGuess: GuessResult = {
                name: searchQuery.toUpperCase(),
                isCorrect: data.isCorrect,
            };

            setGuesses(prev => [newGuess, ...prev]);
            setSearchQuery('');

            if (data.isCorrect || data.gameOver) {
                setGameOver(true);
                setWon(data.isCorrect);
                if (data.solution) {
                    setSolution(data.solution);
                }
                setTimeout(() => setShowResult(true), 1500);
            }

        } catch (error) {
            toast({
                title: 'Error',
                description: error instanceof Error ? error.message : 'Failed to submit guess',
                variant: 'destructive',
            });
        } finally {
            setIsSubmitting(false);
        }
    };

    const remainingGuesses = maxGuesses - guesses.length;

    // Helper to format clue keys
    const formatClueKey = (key: string) => {
        return key
            .replace(/([A-Z])/g, ' $1')
            .replace(/^./, str => str.toUpperCase());
    };

    // Helper to get icon for clue key
    const getClueIcon = (key: string) => {
        const lowerKey = key.toLowerCase();
        if (lowerKey.includes('sport')) return <Medal className="w-4 h-4" />;
        if (lowerKey.includes('team')) return <Flag className="w-4 h-4" />;
        if (lowerKey.includes('age')) return <Calendar className="w-4 h-4" />;
        if (lowerKey.includes('number')) return <Hash className="w-4 h-4" />;
        if (lowerKey.includes('cham') || lowerKey.includes('award') || lowerKey.includes('slam')) return <Trophy className="w-4 h-4" />;
        return <User className="w-4 h-4" />;
    };

    return (
        <div className="flex flex-col items-center gap-8 py-6 w-full max-w-2xl mx-auto px-4">
            {/* Header */}
            <div className="text-center space-y-2">
                <h2 className="text-2xl font-bold tracking-tight">
                    Guess the {gameType === 'ATHLETE' ? 'Athlete' : 'Team'}
                </h2>
                <div className="flex items-center justify-center gap-2 text-sm text-muted-foreground">
                    <span className={cn(
                        "font-medium",
                        remainingGuesses <= 2 ? "text-red-500" : "text-emerald-500"
                    )}>
                        {remainingGuesses} attempts remaining
                    </span>
                </div>
            </div>

            {/* Profile Card */}
            <Card className="w-full bg-card/50 backdrop-blur-sm border-primary/20 shadow-lg">
                <CardHeader className="pb-2">
                    <CardTitle className="text-lg font-medium flex items-center gap-2">
                        <User className="w-5 h-5 text-primary" />
                        Player Profile
                    </CardTitle>
                </CardHeader>
                <CardContent className="grid grid-cols-2 md:grid-cols-3 gap-4 pt-4">
                    {clues && Object.entries(clues).map(([key, value]) => (
                        <div key={key} className="flex flex-col gap-1 p-3 rounded-lg bg-accent/50 border border-border/50">
                            <div className="flex items-center gap-2 text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                                {getClueIcon(key)}
                                {formatClueKey(key)}
                            </div>
                            <div className="text-sm md:text-base font-bold text-foreground truncate" title={String(value)}>
                                {String(value)}
                            </div>
                        </div>
                    ))}
                </CardContent>
            </Card>

            {/* Search Input */}
            {!gameOver && (
                <div className="w-full max-w-md space-y-4">
                    <div className="flex gap-2">
                        <div className="relative flex-1">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                            <Input
                                type="text"
                                placeholder={`Enter ${gameType === 'ATHLETE' ? 'athlete' : 'team'} name...`}
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && handleSubmit()}
                                className="pl-10 bg-background/50 border-primary/20 focus-visible:ring-primary/30 h-11"
                                disabled={isSubmitting}
                                autoFocus
                            />
                        </div>
                        <Button
                            onClick={handleSubmit}
                            disabled={!searchQuery.trim() || isSubmitting}
                            className="h-11 px-6 font-semibold"
                            size="lg"
                        >
                            Guess
                        </Button>
                    </div>
                </div>
            )}

            {/* Guesses List */}
            {guesses.length > 0 && (
                <div className="w-full max-w-md space-y-2">
                    <div className="text-sm font-medium text-muted-foreground px-1">
                        Recent Guesses
                    </div>
                    <div className="space-y-2">
                        <AnimatePresence mode="popLayout">
                            {guesses.map((guess, i) => (
                                <motion.div
                                    key={`${guess.name}-${i}`}
                                    initial={{ opacity: 0, y: -20, scale: 0.95 }}
                                    animate={{ opacity: 1, y: 0, scale: 1 }}
                                    exit={{ opacity: 0, scale: 0.9 }}
                                    className={cn(
                                        "flex items-center justify-between p-3 rounded-lg border shadow-sm backdrop-blur-sm",
                                        guess.isCorrect
                                            ? "bg-emerald-500/10 border-emerald-500/50 text-emerald-700 dark:text-emerald-400"
                                            : "bg-background/80 border-border text-muted-foreground"
                                    )}
                                >
                                    <span className="font-semibold tracking-wide">{guess.name}</span>
                                    {guess.isCorrect ? (
                                        <Badge variant="outline" className="bg-emerald-500/20 text-emerald-600 border-emerald-500/30">
                                            Correct
                                        </Badge>
                                    ) : (
                                        <X className="w-4 h-4 opacity-50" />
                                    )}
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </div>
                </div>
            )}

            {/* Result Modal */}
            <AnimatePresence>
                {showResult && (
                    <DailyGameResult
                        won={won}
                        guesses={guesses.map(g => ({
                            letter: '',
                            status: g.isCorrect ? 'correct' : 'absent'
                        })) as any} // Keeping compatible with result grid logic
                        maxGuesses={maxGuesses}
                        gameNumber={gameNumber}
                        targetWord={solution}
                        onClose={() => setShowResult(false)}
                    />
                )}
            </AnimatePresence>
        </div>
    );
}

'use client';

import { motion } from 'framer-motion';
import { X, Share2, Trophy, Frown, Sparkles } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { generateShareableGrid, type LetterResult } from '@/lib/utils/daily-game-logic';
import { useToast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';
import { getGradientText, getChipStyles } from '@/lib/showcase-theme';

interface DailyGameResultProps {
    won: boolean;
    guesses: LetterResult[][];
    maxGuesses: number;
    gameNumber: number;
    targetWord?: string;
    onClose: () => void;
}

export function DailyGameResult({
    won,
    guesses,
    maxGuesses,
    gameNumber,
    targetWord,
    onClose,
}: DailyGameResultProps) {
    const { toast } = useToast();

    const handleShare = async () => {
        const shareText = generateShareableGrid(gameNumber, guesses, won, maxGuesses);

        try {
            if (navigator.share) {
                await navigator.share({ text: shareText });
            } else {
                await navigator.clipboard.writeText(shareText);
                toast({
                    title: 'Copied to clipboard!',
                    description: 'Share your results with friends',
                });
            }
        } catch {
            // User cancelled share
        }
    };

    // Calculate XP earned
    const xpEarned = won ? 50 + Math.max(0, (maxGuesses - guesses.length) * 10) : 0;

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4"
            onClick={onClose}
        >
            <motion.div
                initial={{ scale: 0.95, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0.95, opacity: 0 }}
                transition={{ type: 'spring', damping: 30, stiffness: 400 }}
                className="relative w-full max-w-sm bg-card border border-border shadow-2xl overflow-hidden"
                onClick={(e) => e.stopPropagation()}
            >
                {/* Accent bar */}
                <div className={cn(
                    'absolute top-0 left-0 right-0 h-1',
                    won ? 'bg-accent' : 'bg-muted-foreground'
                )} />

                {/* Close button */}
                <button
                    onClick={onClose}
                    className="absolute top-4 right-4 p-2 border border-border hover:bg-muted transition-colors z-10"
                >
                    <X className="w-4 h-4" />
                </button>

                {/* Header */}
                <div className="pt-10 pb-6 px-6 text-center border-b border-border">
                    <motion.div
                        initial={{ scale: 0 }}
                        animate={{ scale: 1 }}
                        transition={{ delay: 0.2, type: 'spring', stiffness: 400 }}
                        className={cn(
                            'inline-flex items-center justify-center w-16 h-16 border-2 mb-4',
                            won ? 'border-accent bg-accent/10' : 'border-border bg-muted'
                        )}
                    >
                        {won ? (
                            <Trophy className="w-8 h-8 text-accent" />
                        ) : (
                            <Frown className="w-8 h-8 text-muted-foreground" />
                        )}
                    </motion.div>

                    <h2 className={cn(
                        "text-3xl font-bold uppercase tracking-tighter font-['Barlow_Condensed',sans-serif] mb-2",
                        won ? getGradientText('accent') : 'text-foreground'
                    )}>
                        {won ? 'VICTORY' : 'GAME OVER'}
                    </h2>

                    {won ? (
                        <p className="text-muted-foreground uppercase text-sm tracking-wide">
                            Solved in {guesses.length}/{maxGuesses} attempts
                        </p>
                    ) : (
                        <p className="text-muted-foreground">
                            The answer was <span className="font-bold text-foreground font-mono">{targetWord}</span>
                        </p>
                    )}
                </div>

                {/* Content */}
                <div className="p-6 space-y-5">
                    {/* XP Earned */}
                    {won && (
                        <motion.div
                            initial={{ y: 20, opacity: 0 }}
                            animate={{ y: 0, opacity: 1 }}
                            transition={{ delay: 0.3 }}
                            className="flex items-center justify-center gap-2 p-4 border border-accent/30 bg-accent/5"
                        >
                            <Sparkles className="w-5 h-5 text-accent" />
                            <span className="text-lg font-bold uppercase tracking-wide text-accent">
                                +{xpEarned} XP
                            </span>
                        </motion.div>
                    )}

                    {/* Mini grid preview */}
                    <div className="flex justify-center gap-0.5">
                        {guesses.map((guess, i) => (
                            <div key={i} className="flex flex-col gap-0.5">
                                {guess.map((letter, j) => (
                                    <div
                                        key={j}
                                        className={cn(
                                            'w-4 h-4',
                                            letter.status === 'correct' ? 'bg-accent' :
                                                letter.status === 'present' ? 'bg-warning' :
                                                    'bg-muted'
                                        )}
                                    />
                                ))}
                            </div>
                        ))}
                    </div>

                    {/* Share Button */}
                    <Button
                        onClick={handleShare}
                        className={cn(
                            "w-full h-12 font-bold uppercase tracking-widest text-sm gap-2",
                            won ? 'bg-primary text-primary-foreground' : 'bg-muted text-foreground'
                        )}
                    >
                        <Share2 className="w-4 h-4" />
                        Share Results
                    </Button>

                    {/* Countdown notice */}
                    <p className="text-center text-xs text-muted-foreground uppercase tracking-wide">
                        New challenge at midnight IST
                    </p>
                </div>
            </motion.div>
        </motion.div>
    );
}

'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowUp, ArrowDown, Check, HelpCircle } from 'lucide-react';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { DailyGameResult } from './DailyGameResult';
import { useToast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';

interface StatGuessGameProps {
    gameId: string;
    maxGuesses: number;
    clues?: { description?: string; hint?: string; player?: string; category?: string };
    initialGuesses?: string[];
    isCompleted?: boolean;
    targetValue?: string;
    gameNumber: number;
}

interface StatGuess {
    value: string;
    direction: 'correct' | 'higher' | 'lower';
}

export function StatGuessGame({
    gameId,
    maxGuesses,
    clues,
    initialGuesses = [],
    isCompleted = false,
    targetValue,
    gameNumber,
}: StatGuessGameProps) {
    const [guesses, setGuesses] = useState<StatGuess[]>([]);
    const [currentGuess, setCurrentGuess] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [gameOver, setGameOver] = useState(isCompleted);
    const [won, setWon] = useState(false);
    const [showResult, setShowResult] = useState(false);
    const [solution, setSolution] = useState(targetValue);
    const { toast } = useToast();

    const handleSubmit = async () => {
        if (!currentGuess.trim() || isSubmitting) return;

        const numValue = parseFloat(currentGuess);
        if (isNaN(numValue)) {
            toast({
                title: 'Invalid number',
                description: 'Please enter a valid number',
                variant: 'destructive',
            });
            return;
        }

        setIsSubmitting(true);

        try {
            const response = await fetch('/api/daily/guess', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ gameId, guess: currentGuess }),
            });

            const data = await response.json();

            if (!response.ok) {
                throw new Error(data.error || 'Failed to submit guess');
            }

            const newGuess: StatGuess = {
                value: currentGuess,
                direction: data.feedback?.direction || 'wrong',
            };

            setGuesses(prev => [...prev, newGuess]);
            setCurrentGuess('');

            if (data.isCorrect || data.gameOver) {
                setGameOver(true);
                setWon(data.isCorrect);
                if (data.solution) {
                    setSolution(data.solution);
                }
                setTimeout(() => setShowResult(true), 500);
            }

        } catch (error) {
            toast({
                title: 'Error',
                description: error instanceof Error ? error.message : 'Failed to submit guess',
                variant: 'destructive',
            });
        } finally {
            setIsSubmitting(false);
        }
    };

    const remainingGuesses = maxGuesses - guesses.length;

    return (
        <div className="flex flex-col items-center gap-8 py-4 w-full max-w-md mx-auto px-4">
            {/* Question Card */}
            <motion.div
                className="w-full p-6 bg-gradient-to-br from-primary/10 to-primary/5 rounded-2xl border border-primary/20"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
            >
                <div className="flex items-start gap-3 mb-4">
                    <HelpCircle className="w-6 h-6 text-primary flex-shrink-0 mt-0.5" />
                    <div>
                        <h2 className="text-lg font-semibold mb-1">
                            {clues?.description || 'Guess the Stat'}
                        </h2>
                        {clues?.hint && (
                            <p className="text-sm text-muted-foreground">{clues.hint}</p>
                        )}
                        {clues?.player && (
                            <p className="text-sm font-medium text-primary mt-2">
                                Player: {clues.player}
                            </p>
                        )}
                    </div>
                </div>
            </motion.div>

            {/* Previous Guesses */}
            <div className="w-full space-y-3">
                <AnimatePresence>
                    {guesses.map((guess, i) => (
                        <motion.div
                            key={i}
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: i * 0.1 }}
                            className={cn(
                                'flex items-center justify-between p-4 rounded-xl',
                                guess.direction === 'correct' && 'bg-emerald-500/20 border border-emerald-500/30',
                                guess.direction === 'higher' && 'bg-amber-500/20 border border-amber-500/30',
                                guess.direction === 'lower' && 'bg-amber-500/20 border border-amber-500/30',
                            )}
                        >
                            <span className="text-xl font-bold">{guess.value}</span>
                            <div className={cn(
                                'flex items-center gap-2 px-3 py-1.5 rounded-full font-medium',
                                guess.direction === 'correct' && 'bg-emerald-500 text-white',
                                guess.direction === 'higher' && 'bg-amber-500 text-white',
                                guess.direction === 'lower' && 'bg-amber-500 text-white',
                            )}>
                                {guess.direction === 'correct' ? (
                                    <>
                                        <Check className="w-4 h-4" />
                                        Correct!
                                    </>
                                ) : guess.direction === 'higher' ? (
                                    <>
                                        <ArrowUp className="w-4 h-4" />
                                        Higher
                                    </>
                                ) : (
                                    <>
                                        <ArrowDown className="w-4 h-4" />
                                        Lower
                                    </>
                                )}
                            </div>
                        </motion.div>
                    ))}
                </AnimatePresence>
            </div>

            {/* Input */}
            {!gameOver && (
                <div className="w-full space-y-4">
                    <div className="flex gap-2">
                        <Input
                            type="number"
                            placeholder="Enter your guess..."
                            value={currentGuess}
                            onChange={(e) => setCurrentGuess(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleSubmit()}
                            className="text-center text-xl font-bold h-14"
                            disabled={isSubmitting}
                        />
                        <Button
                            onClick={handleSubmit}
                            disabled={!currentGuess.trim() || isSubmitting}
                            className="h-14 px-6"
                        >
                            Guess
                        </Button>
                    </div>
                    <p className="text-center text-sm text-muted-foreground">
                        {remainingGuesses} guesses remaining
                    </p>
                </div>
            )}

            {/* Game Over */}
            {gameOver && !won && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="text-center p-4 bg-muted rounded-xl"
                >
                    <p className="text-lg">The answer was <span className="font-bold text-primary">{solution}</span></p>
                </motion.div>
            )}

            {/* Result Modal */}
            <AnimatePresence>
                {showResult && (
                    <DailyGameResult
                        won={won}
                        guesses={[]} // Simplified for stat mode

                        maxGuesses={maxGuesses}
                        gameNumber={gameNumber}
                        targetWord={solution}
                        onClose={() => setShowResult(false)}
                    />
                )}
            </AnimatePresence>
        </div>
    );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { WordleBoard } from './WordleBoard';
import { VirtualKeyboard } from './VirtualKeyboard';
import { DailyGameResult } from './DailyGameResult';
import type { LetterResult, LetterStatus } from '@/lib/utils/daily-game-logic';
import { useToast } from '@/hooks/use-toast';

interface WordleGameProps {
    gameId: string;
    wordLength: number;
    maxGuesses: number;
    initialGuesses?: LetterResult[][];
    initialLetterStatuses?: Record<string, LetterStatus>;
    isCompleted?: boolean;
    targetWord?: string;
    gameNumber: number;
}

export function WordleGame({
    gameId,
    wordLength,
    maxGuesses,
    initialGuesses = [],
    initialLetterStatuses = {},
    isCompleted = false,
    targetWord,
    gameNumber,
}: WordleGameProps) {
    const [guesses, setGuesses] = useState<LetterResult[][]>(initialGuesses);
    const [solution, setSolution] = useState(targetWord);
    const [currentGuess, setCurrentGuess] = useState('');
    const [letterStatuses, setLetterStatuses] = useState<Record<string, LetterStatus>>(initialLetterStatuses);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isRevealing, setIsRevealing] = useState(false);
    const [gameOver, setGameOver] = useState(isCompleted);
    const [won, setWon] = useState(initialGuesses.some(g => g.every(l => l.status === 'correct')));
    const [showResult, setShowResult] = useState(false);
    const { toast } = useToast();

    // Listen for physical keyboard
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (gameOver || isSubmitting) return;

            if (e.key === 'Enter') {
                handleKeyPress('ENTER');
            } else if (e.key === 'Backspace') {
                handleKeyPress('BACKSPACE');
            } else if (/^[a-zA-Z]$/.test(e.key)) {
                handleKeyPress(e.key.toUpperCase());
            }
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [currentGuess, gameOver, isSubmitting]);

    const handleKeyPress = useCallback((key: string) => {
        if (gameOver || isSubmitting) return;

        if (key === 'BACKSPACE') {
            setCurrentGuess(prev => prev.slice(0, -1));
        } else if (key === 'ENTER') {
            if (currentGuess.length === wordLength) {
                submitGuess();
            } else {
                toast({
                    title: 'Not enough letters',
                    description: `Word must be ${wordLength} letters`,
                    variant: 'destructive',
                });
            }
        } else if (currentGuess.length < wordLength && /^[A-Z]$/.test(key)) {
            setCurrentGuess(prev => prev + key);
        }
    }, [currentGuess, wordLength, gameOver, isSubmitting]);

    const submitGuess = async () => {
        if (currentGuess.length !== wordLength || isSubmitting) return;

        setIsSubmitting(true);

        try {
            const response = await fetch('/api/daily/guess', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ gameId, guess: currentGuess }),
            });

            const data = await response.json();

            if (!response.ok) {
                throw new Error(data.error || 'Failed to submit guess');
            }

            // Update letter statuses
            const feedback = data.feedback as LetterResult[];
            const newStatuses = { ...letterStatuses };
            feedback.forEach(({ letter, status }) => {
                // Only upgrade status (absent -> present -> correct)
                const currentStatus = newStatuses[letter];
                if (!currentStatus ||
                    (currentStatus === 'absent' && status !== 'absent') ||
                    (currentStatus === 'present' && status === 'correct')) {
                    newStatuses[letter] = status;
                }
            });
            setLetterStatuses(newStatuses);

            // Animate reveal
            setIsRevealing(true);
            setTimeout(() => {
                setGuesses(prev => [...prev, feedback]);
                setCurrentGuess('');
                setIsRevealing(false);

                if (data.isCorrect || data.gameOver) {
                    setGameOver(true);
                    setWon(data.isCorrect);
                    if (data.solution) {
                        setSolution(data.solution);
                    }
                    setTimeout(() => setShowResult(true), 500);
                }
            }, wordLength * 100 + 500);

        } catch (error) {
            toast({
                title: 'Error',
                description: error instanceof Error ? error.message : 'Failed to submit guess',
                variant: 'destructive',
            });
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="flex flex-col items-center gap-6 sm:gap-8 py-4">
            <WordleBoard
                guesses={guesses}
                currentGuess={currentGuess}
                maxGuesses={maxGuesses}
                wordLength={wordLength}
                isRevealing={isRevealing}
            />

            <VirtualKeyboard
                onKeyPress={handleKeyPress}
                letterStatuses={letterStatuses}
                disabled={gameOver || isSubmitting || isRevealing}
            />

            <AnimatePresence>
                {showResult && (
                    <DailyGameResult
                        won={won}
                        guesses={guesses}
                        maxGuesses={maxGuesses}
                        gameNumber={gameNumber}
                        targetWord={solution}
                        onClose={() => setShowResult(false)}
                    />
                )}
            </AnimatePresence>
        </div>
    );
}

