"use client";

import { cn } from "@/lib/utils";
import { RarityBadge } from "./RarityBadge";
import { Lock, Plus, Check } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

export type CellState = "empty" | "active" | "correct" | "wrong" | "disabled" | "locked";

interface GridCellProps {
    row: number;
    col: number;
    state: CellState;

    // Data for Filled State
    playerName?: string;
    playerImageUrl?: string;
    rarity?: number;
    points?: number;

    // Interactivity
    onClick?: () => void;
    disabled?: boolean;

    className?: string;
}

export function GridCell({
    row,
    col,
    state,
    playerName,
    playerImageUrl,
    rarity,
    points,
    onClick,
    disabled,
    className
}: GridCellProps) {

    const isInteractive = (state === "empty" || state === "active") && !disabled;
    const isFilled = state === "correct";
    const isWrong = state === "wrong" || state === "locked";

    return (
        <div
            onClick={isInteractive ? onClick : undefined}
            className={cn(
                "relative aspect-square w-full rounded-xl border transition-all duration-200 overflow-hidden group select-none",
                // Empty State styling
                state === "empty" && "bg-card hover:bg-accent/50 hover:border-primary/50 cursor-pointer shadow-sm",
                // Active/Focused
                state === "active" && "bg-accent border-primary ring-2 ring-primary ring-offset-2 z-10",
                // Wrong/Locked
                isWrong && "bg-muted/50 border-transparent cursor-not-allowed opacity-80 grayscale",
                // Correct (Base)
                isFilled && "bg-emerald-50 border-emerald-200 cursor-default",

                className
            )}
        >
            <AnimatePresence mode="wait">

                {/* IDLE / ACTIVE STATE */}
                {(state === "empty" || state === "active") && (
                    <motion.div
                        key="idle"
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="absolute inset-0 flex items-center justify-center text-muted-foreground/30 group-hover:text-primary/70 transition-colors"
                    >
                        <Plus className={cn("w-8 h-8", state === "active" && "scale-110 text-primary")} />
                    </motion.div>
                )}

                {/* LOCKED / WRONG STATE */}
                {isWrong && (
                    <motion.div
                        key="wrong"
                        initial={{ scale: 0.8, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        className="absolute inset-0 flex flex-col items-center justify-center text-muted-foreground"
                    >
                        <Lock className="w-6 h-6 mb-1 opacity-50" />
                        <span className="text-[10px] font-bold uppercase tracking-wider opacity-60">Locked</span>
                    </motion.div>
                )}

                {/* CORRECT STATE */}
                {isFilled && (
                    <motion.div
                        key="correct"
                        initial={{ rotateY: 90, opacity: 0 }}
                        animate={{ rotateY: 0, opacity: 1 }}
                        transition={{ type: "spring", stiffness: 260, damping: 20 }}
                        className="absolute inset-0 flex flex-col"
                    >
                        {/* Background Image Layer */}
                        {playerImageUrl ? (
                            <div className="absolute inset-0 bg-cover bg-center bg-no-repeat opacity-90 transition-transform duration-700 hover:scale-105"
                                style={{ backgroundImage: `url(${playerImageUrl})` }}
                            />
                        ) : (
                            // Fallback Pattern if no image
                            <div className="absolute inset-0 bg-gradient-to-br from-emerald-500/10 to-blue-500/10" />
                        )}

                        {/* Gradient Overlay for Text Readability */}
                        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/40 to-transparent" />

                        {/* Content Layer */}
                        <div className="relative z-10 flex flex-col justify-end h-full p-2 md:p-3 text-white">
                            {/* Top Right: Rarity */}
                            {rarity !== undefined && (
                                <div className="absolute top-2 right-2">
                                    <RarityBadge percentage={rarity} />
                                </div>
                            )}

                            {/* Bottom: Name */}
                            <div className="flex flex-col">
                                <span className="text-[10px] uppercase tracking-wider text-emerald-300 font-bold mb-0.5 flex items-center gap-1">
                                    <Check className="w-3 h-3" /> Correct
                                </span>
                                <span className="font-bold text-sm md:text-base leading-tight line-clamp-2 text-balance shadow-black drop-shadow-md">
                                    {playerName || "Unknown Player"}
                                </span>
                                {points && (
                                    <span className="text-[10px] text-white/70 font-mono mt-0.5">
                                        +{points} pts
                                    </span>
                                )}
                            </div>
                        </div>
                    </motion.div>
                )}

            </AnimatePresence>
        </div>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { useToast } from "@/hooks/use-toast";
import { GridHeader } from "./GridHeader";
import { GridBoard, GridStateItem } from "./GridBoard";
import { PlayerSearchModal } from "./PlayerSearchModal";
import { Button } from "@/components/ui/button";
import { trackEvent } from "@/lib/analytics";
import confetti from "canvas-confetti";
import { Loader2 } from "lucide-react";
import { GridQuiz } from "@prisma/client";

interface GridGameProps {
    grid: GridQuiz;
    userId: string;
}

export function GridGame({ grid, userId }: GridGameProps) {
    const router = useRouter();
    const { toast } = useToast();
    const [initLoading, setInitLoading] = useState(true);

    // Game State
    const [attemptId, setAttemptId] = useState<string | null>(null);
    const [gridState, setGridState] = useState<GridStateItem[][]>([]);
    const [score, setScore] = useState(0);
    const [lives, setLives] = useState(9);
    const [gameStatus, setGameStatus] = useState<"playing" | "completed" | "lost">("playing");

    // Modal State
    const [activeCell, setActiveCell] = useState<{ r: number, c: number } | null>(null);
    const [isModalOpen, setIsModalOpen] = useState(false);

    // Initialization
    useEffect(() => {
        const initGame = async () => {
            try {
                setInitLoading(true);
                // Create or resume attempt
                const res = await fetch(`/api/grids/${grid.id}/attempt`, {
                    method: "POST",
                });

                if (!res.ok) throw new Error("Failed to start game");

                const data = await res.json();
                const attempt = data.data;

                setAttemptId(attempt.id);

                // Initialize Grid State (3x3)
                // TODO: If resuming, fetch existing answers and populate grid
                const initialGrid: GridStateItem[][] = Array(3).fill(null).map((_, r) =>
                    Array(3).fill(null).map((_, c) => ({
                        row: r,
                        col: c,
                        state: "empty"
                    }))
                );

                setGridState(initialGrid);
                setInitLoading(false);
                trackEvent("grid_start", { quizId: grid.id, quizTitle: grid.title });

            } catch (error) {
                console.error(error);
                toast({ title: "Error", description: "Could not load the grid.", variant: "destructive" });
            }
        };

        initGame();
    }, [grid.id, grid.title, toast]);

    // Timing
    const answerStartTimeRef = useRef<number>(0);

    // Handle Cell Click
    const onCellClick = (r: number, c: number) => {
        if (gameStatus !== "playing") return;

        const cell = gridState[r][c];
        if (cell.state !== "empty" && cell.state !== "active") return;

        // Reset other active cells and set new active
        setGridState(prev => prev.map(row => row.map(cell => ({
            ...cell,
            state: (cell.row === r && cell.col === c) ? "active" : (cell.state === "active" ? "empty" : cell.state)
        }))));

        setActiveCell({ r, c });
        answerStartTimeRef.current = Date.now();
        setIsModalOpen(true);
    };

    // Handle Modal Close
    const onModalClose = () => {
        setIsModalOpen(false);
        if (activeCell) {
            setGridState(prev => prev.map(row => row.map(cell => ({
                ...cell,
                state: cell.state === "active" ? "empty" : cell.state
            }))));
            setActiveCell(null);
        }
    };

    // Handle Answer Submission
    const onSubmitAnswer = async (answer: string) => {
        if (!attemptId || !activeCell) return;

        const { r, c } = activeCell;

        try {
            const res = await fetch(`/api/grids/${grid.id}/submit`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    attemptId,
                    cellRow: r,
                    cellCol: c,
                    answer,
                })
            });

            const responseData = await res.json();
            if (!res.ok) throw new Error(responseData.error || "Failed to submit answer");

            const result = responseData.data; // { isCorrect, rarity, message }

            // Update Grid State
            setGridState(prev => {
                const newGrid = [...prev.map(row => [...row])];
                const cell = newGrid[r][c];

                if (result.isCorrect) {
                    cell.state = "correct";
                    cell.playerName = answer; // Or matched name from backend if available
                    cell.rarity = (result.rarity || 0) * 1; // Assuming rarity is 0-100? Backend sent 1-20 mocked.
                    // cell.points = ... 

                    trackEvent("grid_correct", { quizId: grid.id, cell: `${r}x${c}`, rarity: cell.rarity });
                    setScore(s => s + 1);
                } else {
                    cell.state = "wrong";
                    setLives(l => Math.max(0, l - 1));
                    trackEvent("grid_wrong", { quizId: grid.id, cell: `${r}x${c}` });
                }

                return newGrid;
            });

            // Check Win/Loss
            if (result.isCorrect) {
                // Check if all filled
                // We need to wait for state update or check explicitly
                const correctCount = gridState.flat().filter(c => c.state === "correct").length + 1;
                if (correctCount === 9) {
                    setGameStatus("completed");
                    confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
                    // Navigate to results
                    setTimeout(() => router.push(`/grids/${grid.slug}/results/${attemptId}`), 2000);
                }
            } else {
                if (lives - 1 <= 0) {
                    setGameStatus("lost");
                    toast({ title: "Game Over", description: "You ran out of lives!", variant: "destructive" });
                    setTimeout(() => router.push(`/grids/${grid.slug}/results/${attemptId}`), 2000);
                }
            }

            onModalClose();

        } catch (error) {
            console.error(error);
            toast({ title: "Error", description: "Failed to submit answer.", variant: "destructive" });
            // Do not close modal on error to allow retry? 
            // Or close it?
            setIsModalOpen(false);
        }
    };

    if (initLoading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader2 className="w-10 h-10 animate-spin text-primary" />
            </div>
        );
    }

    const rows = grid.rows as string[];
    const cols = grid.cols as string[];

    return (
        <div className="min-h-screen bg-background flex flex-col items-center py-6 md:py-10 animate-in fade-in duration-500">

            <GridHeader
                quizTitle={grid.title}
                score={score}
                lives={lives}
                maxLives={9}
            />

            <GridBoard
                rows={rows}
                cols={cols}
                gridState={gridState}
                onCellClick={onCellClick}
            />

            <div className="mt-12 flex gap-4">
                <Button variant="ghost" className="text-muted-foreground hover:text-destructive transition-colors"
                    onClick={() => {
                        if (confirm("Are you sure you want to give up?")) {
                            router.push(`/grids/${grid.slug}/results/${attemptId}`);
                        }
                    }}
                >
                    Give Up
                </Button>
            </div>

            {activeCell && (
                <PlayerSearchModal
                    isOpen={isModalOpen}
                    onClose={onModalClose}
                    onSubmit={onSubmitAnswer}
                    rowLabel={rows[activeCell.r]}
                    colLabel={cols[activeCell.c]}
                />
            )}
        </div>
    );
}

