"use client";

import { useEffect, useState } from "react";
import { GridResults } from "./GridResults";
import { GridQuiz, GridAttempt, GridAnswer } from "@prisma/client";
import { Loader2 } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

interface GridResultsPageProps {
    quizSlug: string;
    attemptId: string;
}

type AttemptWithDetails = GridAttempt & {
    gridQuiz: GridQuiz;
    answers: GridAnswer[];
};

export default function GridResultsPage({ quizSlug, attemptId }: GridResultsPageProps) {
    const [loading, setLoading] = useState(true);
    const [attempt, setAttempt] = useState<AttemptWithDetails | null>(null);
    const { toast } = useToast();

    useEffect(() => {
        const fetchResults = async () => {
            try {
                // We can fetch attempt details. Need an API route for this if not existing.
                // Currently we have /api/grids/[id]/attempt (POST), we need a GET for attempt details.
                const res = await fetch(`/api/grids/attempts/${attemptId}`);
                if (!res.ok) throw new Error("Failed to fetch results");
                const data = await res.json();
                setAttempt(data.data);
            } catch (error) {
                console.error(error);
                toast({ title: "Error", description: "Failed to load results.", variant: "destructive" });
            } finally {
                setLoading(false);
            }
        };

        fetchResults();
    }, [attemptId, toast]);

    if (loading) {
        return (
            <div className="min-h-[60vh] flex items-center justify-center">
                <Loader2 className="w-10 h-10 animate-spin text-primary" />
            </div>
        );
    }

    if (!attempt) {
        return (
            <div className="min-h-[60vh] flex items-center justify-center">
                <p className="text-muted-foreground">Results not found.</p>
            </div>
        );
    }

    // Map GridAnswer to the format expected by GridResults
    const gridAnswers = Array(9).fill(null).map((_, i) => {
        const r = Math.floor(i / 3);
        const c = i % 3;
        const cellId = `${r}-${c}`;
        const ans = attempt.answers.find(a => a.cellId === cellId);

        if (!ans) return null;

        return {
            questionId: ans.id,
            questionText: "", // Not used in display usually
            isCorrect: ans.isValid,
            textAnswer: ans.playerInput,
            totalPoints: 1, // Simple scoring for now
            basePoints: 1,
            gridData: {
                rarity: ans.rarityScore || 0,
                pickedByPercent: ans.rarityScore || 0,
                acceptedAnswers: [], // We don't have this in attempt usually
            }
        };
    }).filter(Boolean) as any[];

    return (
        <GridResults
            quizTitle={attempt.gridQuiz.title}
            gridConfig={{
                rows: attempt.gridQuiz.rows as string[],
                cols: attempt.gridQuiz.cols as string[],
            }}
            answers={gridAnswers}
            totalScore={attempt.score}
            correctCount={attempt.score}
        />
    );
}

"use client";

import { useState, useEffect, useMemo } from "react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import Link from "next/link";
import {
    Trophy,
    Share2,
    RotateCcw,
    Home,
    CheckCircle2,
    XCircle,
    Sparkles
} from "lucide-react";
import confetti from "canvas-confetti";
import { useToast } from "@/hooks/use-toast";

// Types
interface GridResultAnswer {
    questionId: string;
    questionText: string;
    isCorrect: boolean;
    textAnswer?: string | null;
    gridData?: {
        rarity: number;
        pickedByPercent: number;
        acceptedAnswers: string[];
    };
    basePoints: number;
    totalPoints: number;
}

interface GridResultsPageProps {
    quizTitle: string;
    quizSlug: string;
    attemptId: string;
    score: number;
    totalQuestions: number;
    gridConfig: {
        rows: string[];
        cols: string[];
    };
    answers: GridResultAnswer[];
    user: {
        name: string;
        image?: string | null;
    };
}

export function GridResultsPage({
    quizTitle,
    quizSlug,
    score,
    gridConfig,
    answers = [],
}: GridResultsPageProps) {
    const { toast } = useToast();

    // Safety checks with defaults
    const rows = gridConfig?.rows || [];
    const cols = gridConfig?.cols || [];

    // Stats Calculation
    const correctCount = answers.filter(a => a.isCorrect).length;

    // Rarity Calculation
    const averageRarity = useMemo(() => {
        const correctAnswers = answers.filter(a => a.isCorrect);
        if (correctAnswers.length === 0) return 0;
        const totalRarity = correctAnswers.reduce((sum, a) => sum + (a.gridData?.pickedByPercent || 0), 0);
        return Math.round(totalRarity / correctAnswers.length);
    }, [answers]);

    // Insights
    const rarestFind = useMemo(() => {
        const correct = answers.filter(a => a.isCorrect && a.gridData);
        if (correct.length === 0) return null;
        return correct.reduce((prev, curr) =>
            (prev.gridData!.pickedByPercent < curr.gridData!.pickedByPercent) ? prev : curr
        );
    }, [answers]);

    // Trigger celebration
    useEffect(() => {
        if (correctCount > 4) {
            const end = Date.now() + 1000;
            const colors = ['#10b981', '#a855f7'];

            (function frame() {
                confetti({
                    particleCount: 2,
                    angle: 60,
                    spread: 55,
                    origin: { x: 0 },
                    colors: colors
                });
                confetti({
                    particleCount: 2,
                    angle: 120,
                    spread: 55,
                    origin: { x: 1 },
                    colors: colors
                });

                if (Date.now() < end) {
                    requestAnimationFrame(frame);
                }
            }());
        }
    }, [correctCount]);

    const handleShare = async () => {
        let gridString = "";
        for (let r = 0; r < 3; r++) {
            for (let c = 0; c < 3; c++) {
                const idx = r * 3 + c;
                const ans = answers[idx];
                gridString += ans?.isCorrect ? "🟩" : "⬛";
            }
            gridString += "\n";
        }

        const shareText = `IMMACULATE GRID: ${quizTitle}\nScore: ${correctCount}/9\nRarity: ${averageRarity}%\n\n${gridString}\nPlay now: ${window.location.host}/quizzes/${quizSlug}`;

        try {
            if (navigator.share) {
                await navigator.share({
                    title: quizTitle,
                    text: shareText,
                });
            } else {
                await navigator.clipboard.writeText(shareText);
                toast({ title: "Copied to clipboard!", description: "Share your results with friends." });
            }
        } catch (err) {
            console.error("Share failed:", err);
        }
    };

    return (
        <div className="w-full max-w-4xl mx-auto space-y-8 py-8 animate-in fade-in duration-500">
            {/* Header / Stats */}
            <div className="text-center space-y-4">
                <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-secondary text-secondary-foreground text-xs font-bold uppercase tracking-widest">
                    <Trophy className="w-3.5 h-3.5" />
                    <span>Results</span>
                </div>
                <h1 className="text-3xl font-bold tracking-tight text-foreground">{quizTitle}</h1>

                <div className="grid grid-cols-2 gap-4 max-w-sm mx-auto">
                    <Card className="border-emerald-500/20 bg-emerald-500/5">
                        <CardHeader className="p-4 pb-2">
                            <CardTitle className="text-xs uppercase text-muted-foreground font-bold">Score</CardTitle>
                        </CardHeader>
                        <CardContent className="p-4 pt-0">
                            <div className="text-3xl font-black text-emerald-600 dark:text-emerald-400">
                                {correctCount}/9
                            </div>
                        </CardContent>
                    </Card>
                    <Card className="border-purple-500/20 bg-purple-500/5">
                        <CardHeader className="p-4 pb-2">
                            <CardTitle className="text-xs uppercase text-muted-foreground font-bold">Rarity</CardTitle>
                        </CardHeader>
                        <CardContent className="p-4 pt-0">
                            <div className="text-3xl font-black text-purple-600 dark:text-purple-400">
                                {correctCount > 0 ? `${averageRarity}%` : "—"}
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>

            {/* Grid */}
            <Card className="overflow-hidden bg-card">
                <CardContent className="p-6">
                    <div className="grid grid-cols-[auto_1fr_1fr_1fr] gap-2 md:gap-4 max-w-2xl mx-auto">
                        {/* Corner */}
                        <div className="aspect-square" />

                        {/* Col Headers */}
                        {cols.map((col, i) => (
                            <div key={`col-${i}`} className="flex items-center justify-center text-center p-2">
                                <span className="text-xs font-bold uppercase text-muted-foreground">{col}</span>
                            </div>
                        ))}

                        {/* Rows */}
                        {rows.map((row, r) => (
                            <div key={`row-${r}`} className="contents">
                                {/* Row Header */}
                                <div className="flex items-center justify-center text-center p-2">
                                    <span className="text-xs font-bold uppercase text-muted-foreground vertical-lr md:horizontal-tb">{row}</span>
                                </div>

                                {/* Cells */}
                                {cols.map((_, c) => {
                                    const idx = r * 3 + c;
                                    const answer = answers[idx];
                                    return (
                                        <div
                                            key={`cell-${idx}`}
                                            className={cn(
                                                "aspect-[4/3] rounded-md border flex flex-col items-center justify-center p-1 text-center relative overflow-hidden transition-all",
                                                answer?.isCorrect
                                                    ? "bg-emerald-50 dark:bg-emerald-950/20 border-emerald-200 dark:border-emerald-800"
                                                    : "bg-muted/50 border-border"
                                            )}
                                        >
                                            {answer?.isCorrect ? (
                                                <>
                                                    <Badge variant="secondary" className="absolute top-1 right-1 text-[9px] px-1 h-3.5 bg-background/80 backdrop-blur-sm">
                                                        {answer.gridData?.pickedByPercent}%
                                                    </Badge>
                                                    <CheckCircle2 className="w-4 h-4 text-emerald-500 mb-1" />
                                                    <span className="text-[10px] md:text-xs font-semibold leading-tight line-clamp-2">
                                                        {answer.textAnswer}
                                                    </span>
                                                </>
                                            ) : (
                                                <>
                                                    <XCircle className="w-4 h-4 text-muted-foreground/30 mb-1" />
                                                    <span className="text-[10px] md:text-xs text-muted-foreground line-clamp-2">
                                                        {answer?.textAnswer || "Empty"}
                                                    </span>
                                                </>
                                            )}
                                        </div>
                                    );
                                })}
                            </div>
                        ))}
                    </div>
                </CardContent>
            </Card>

            {/* Rarest Find */}
            {rarestFind && (
                <div className="max-w-md mx-auto">
                    <div className="bg-gradient-to-r from-purple-500/10 to-blue-500/10 border border-purple-500/20 rounded-xl p-4 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-purple-500/20 rounded-full text-purple-600 dark:text-purple-400">
                                <Sparkles className="w-5 h-5" />
                            </div>
                            <div>
                                <div className="text-xs font-bold uppercase text-purple-600 dark:text-purple-400">Rarest Find</div>
                                <div className="font-bold text-foreground">{rarestFind.textAnswer}</div>
                            </div>
                        </div>
                        <div className="text-2xl font-black text-foreground">
                            {rarestFind.gridData?.pickedByPercent}%
                        </div>
                    </div>
                </div>
            )}

            {/* Actions */}
            <div className="flex flex-col sm:flex-row gap-4 justify-center max-w-md mx-auto">
                <Button onClick={handleShare} className="flex-1" size="lg">
                    <Share2 className="w-4 h-4 mr-2" />
                    Share Result
                </Button>
                <Link href={`/quizzes/${quizSlug}/play`} className="flex-1">
                    <Button variant="outline" className="w-full" size="lg">
                        <RotateCcw className="w-4 h-4 mr-2" />
                        Play Again
                    </Button>
                </Link>
            </div>

            <div className="text-center pt-4">
                <Link href="/quizzes">
                    <Button variant="ghost" size="sm" className="text-muted-foreground">
                        <Home className="w-4 h-4 mr-2" />
                        Back to Quizzes
                    </Button>
                </Link>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { useRouter } from "next/navigation";
import { useToast } from "@/hooks/use-toast";
import { GridHeader } from "./GridHeader";
import { GridBoard, GridStateItem } from "./GridBoard";
import { PlayerSearchModal } from "./PlayerSearchModal";
import { Button } from "@/components/ui/button";
import { trackEvent } from "@/lib/analytics";
import confetti from "canvas-confetti";
import { Loader2 } from "lucide-react";

interface ImmaculateGridProps {
    quizId: string;
    quizTitle: string;
    quizSlug: string;
}

interface GridPlayConfig {
    rows: string[];
    cols: string[];
    scoring?: any;
}

interface Question {
    id: string;
    questionText: string; // "Row: X, Col: Y"
}

export function ImmaculateGrid({ quizId, quizTitle, quizSlug }: ImmaculateGridProps) {
    const router = useRouter();
    const { toast } = useToast();
    const [initLoading, setInitLoading] = useState(true);

    // Game State
    const [attemptId, setAttemptId] = useState<string | null>(null);
    const [gridConfig, setGridConfig] = useState<GridPlayConfig | null>(null);
    const [gridState, setGridState] = useState<GridStateItem[][]>([]);
    const [questions, setQuestions] = useState<Question[]>([]); // 0-8
    const [score, setScore] = useState(0);
    const [lives, setLives] = useState(9);
    const [gameStatus, setGameStatus] = useState<"playing" | "completed" | "lost">("playing");

    // Modal State
    const [activeCell, setActiveCell] = useState<{ r: number, c: number } | null>(null);
    const [isModalOpen, setIsModalOpen] = useState(false);

    // Initialization
    useEffect(() => {
        const initGame = async () => {
            try {
                setInitLoading(true);
                // Create or resume attempt
                const res = await fetch("/api/attempts", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ quizId }),
                });

                if (!res.ok) throw new Error("Failed to start game");

                const data = await res.json();
                const attempt = data.data.attempt;
                // API returns playConfig at top level for new attempts, 
                // or we might need to fallback if structure changes.
                const config = data.data.playConfig || data.data.quiz?.playConfig;
                const questionsList = data.data.questions || [];

                setAttemptId(attempt.id);
                setGridConfig(config);
                setQuestions(questionsList);

                // Initialize Grid State (3x3)
                // Check for existing answers in attempt (resume behavior)
                const initialGrid: GridStateItem[][] = Array(3).fill(null).map((_, r) =>
                    Array(3).fill(null).map((_, c) => ({
                        row: r,
                        col: c,
                        state: "empty"
                    }))
                );

                // TODO: Resume logic would map `attempt.answers` to grid cells here.
                // For now, we assume a fresh start or simple resume logic logic is needed.
                // If the user refreshes, they might lose progress unless we fetch answers.

                setGridState(initialGrid);
                setInitLoading(false);
                trackEvent("grid_start", { quizId, quizTitle });

            } catch (error) {
                console.error(error);
                toast({ title: "Error", description: "Could not load the grid.", variant: "destructive" });
            }
        };

        initGame();
    }, [quizId, quizTitle, toast]);

    // Timing State
    // helper ref for tracking time spent
    const answerStartTimeRef = useRef<number>(0);

    // Handle Cell Click
    const onCellClick = (r: number, c: number) => {
        if (gameStatus !== "playing") return;

        const cell = gridState[r][c];
        if (cell.state !== "empty" && cell.state !== "active") return;

        // Reset other active cells and set new active
        setGridState(prev => prev.map(row => row.map(cell => ({
            ...cell,
            state: (cell.row === r && cell.col === c) ? "active" : (cell.state === "active" ? "empty" : cell.state)
        }))));

        setActiveCell({ r, c });
        answerStartTimeRef.current = Date.now();
        setIsModalOpen(true);
    };

    // Handle Modal Close (Cancel)
    const onModalClose = () => {
        setIsModalOpen(false);
        if (activeCell) {
            setGridState(prev => prev.map(row => row.map(cell => ({
                ...cell,
                state: cell.state === "active" ? "empty" : cell.state
            }))));
            setActiveCell(null);
        }
    };

    // Handle Answer Submission
    const onSubmitAnswer = async (answer: string) => {
        if (!attemptId || !activeCell || !gridConfig) return;

        const { r, c } = activeCell;
        const questionIndex = r * 3 + c;
        const question = questions[questionIndex];
        if (!question) {
            toast({ title: "Error", description: "Question not found for this cell.", variant: "destructive" });
            return;
        }

        const timeSpent = Math.max(1, Math.round((Date.now() - answerStartTimeRef.current) / 1000));

        try {
            const res = await fetch(`/api/attempts/${attemptId}/answers/text`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    questionId: question.id,
                    textAnswer: answer,
                    timeSpent
                })
            });

            const data = await res.json();
            if (!res.ok) throw new Error(data.error || "Failed to submit answer");

            const result = data.data; // { isCorrect, matchedAnswerText, rarity, totalPoints, etc. }

            // Update Grid State
            setGridState(prev => {
                const newGrid = [...prev.map(row => [...row])];
                const cell = newGrid[r][c];

                if (result.isCorrect) {
                    cell.state = "correct";
                    cell.playerName = result.matchedAnswerText;
                    // cell.playerImageUrl = ... // Backend doesn't send image yet?
                    cell.rarity = result.rarity ? result.rarity * 100 : 0; // Convert to %
                    cell.points = result.totalPoints;

                    // Track Event
                    trackEvent("grid_correct", { quizId, cell: `${r}x${c}`, rarity: cell.rarity });
                } else {
                    cell.state = "wrong";
                    setLives(l => Math.max(0, l - 1));
                    trackEvent("grid_wrong", { quizId, cell: `${r}x${c}` });
                }

                return newGrid;
            });

            if (result.isCorrect) {
                setScore(s => s + (result.totalPoints || 0));
                // Trigger Confetti if game won (all 9 correct)
                // Check if all correct
                const isWin = gridState.flat().filter(c => c.state === "correct").length + 1 === 9; // +1 because state update is pending? No, use functional update above or check logic.
                // Actually we can't check 'newGrid' easily inside async without variables.
                // Let's rely on effect or simple check.
                // We won't trigger confetti here immediately to avoid complex state logic, 
                // but we could if we tracked correct count.
            } else {
                // Check Game Over
                if (lives - 1 <= 0) {
                    setGameStatus("lost");
                    toast({ title: "Game Over", description: "You ran out of lives!", variant: "destructive" });
                    router.push(`/quizzes/${quizSlug}/results/${attemptId}`);
                }
            }

            onModalClose();

        } catch (error) {
            console.error(error);
            toast({ title: "Error", description: "Failed to submit answer. Please try again.", variant: "destructive" });
            setIsModalOpen(false); // Close anyway or keep open? Keep open allows retry.
        }
    };

    // Game Over / Win Logic interactions
    useEffect(() => {
        if (lives === 0 && gameStatus !== "lost") {
            setGameStatus("lost");
            // Maybe delay redirect?
        }
    }, [lives, gameStatus]);

    useEffect(() => {
        const correctCount = gridState.flat().filter(c => c.state === "correct").length;
        if (correctCount === 9 && gameStatus !== "completed") {
            setGameStatus("completed");
            confetti({
                particleCount: 150,
                spread: 70,
                origin: { y: 0.6 }
            });
            setTimeout(() => {
                router.push(`/quizzes/${quizSlug}/results/${attemptId}`);
            }, 3000);
        }
    }, [gridState, gameStatus, attemptId, quizSlug, router]);


    if (initLoading || !gridConfig) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader2 className="w-10 h-10 animate-spin text-primary" />
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-background flex flex-col items-center py-6 md:py-10 animate-in fade-in duration-500">

            <GridHeader
                quizTitle={quizTitle}
                score={score}
                lives={lives}
                maxLives={9}
            />

            <GridBoard
                rows={gridConfig.rows}
                cols={gridConfig.cols}
                gridState={gridState}
                onCellClick={onCellClick}
            />

            <div className="mt-12 flex gap-4">
                <Button variant="ghost" className="text-muted-foreground hover:text-destructive transition-colors"
                    onClick={() => {
                        if (confirm("Are you sure you want to give up?")) {
                            router.push(`/quizzes/${quizSlug}/results/${attemptId}`);
                        }
                    }}
                >
                    Give Up
                </Button>
            </div>

            {activeCell && (
                <PlayerSearchModal
                    isOpen={isModalOpen}
                    onClose={onModalClose}
                    onSubmit={onSubmitAnswer}
                    rowLabel={gridConfig.rows[activeCell.r]}
                    colLabel={gridConfig.cols[activeCell.c]}
                />
            )}
        </div>
    );
}

