"use client";

import { useMemo, useRef, useState } from "react";
import { ShowcaseQuizCard } from "./ShowcaseQuizCard";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { ChevronLeft, ChevronRight } from "lucide-react";

interface CarouselItem {
  id: string;
  title: string;
  badgeLabel?: string;
  durationLabel: string;
  playersLabel: string;
  accent: string;
  coverImageUrl?: string | null;
  href?: string;
}

interface ShowcaseQuizCarouselProps {
  items: CarouselItem[];
  className?: string;
}

export function ShowcaseQuizCarousel({ items, className }: ShowcaseQuizCarouselProps) {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(true);

  const handleScroll = () => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
      setShowLeftArrow(scrollLeft > 20);
      setShowRightArrow(scrollLeft < scrollWidth - clientWidth - 20);
    }
  };

  const scroll = (direction: "left" | "right") => {
    if (scrollRef.current) {
      const scrollAmount = 360; // Card width + gap
      scrollRef.current.scrollBy({
        left: direction === "left" ? -scrollAmount : scrollAmount,
        behavior: "smooth",
      });
    }
  };

  return (
    <div className={cn("group relative w-full", className)}>
      {/* Scrollable Container */}
      <div
        ref={scrollRef}
        onScroll={handleScroll}
        className="flex gap-8 overflow-x-auto pb-8 pt-4 scrollbar-hide no-scrollbar -mx-4 px-4 sm:mx-0 sm:px-0"
        style={{ scrollSnapType: "x mandatory", WebkitOverflowScrolling: "touch" }}
      >
        {items.map((item) => (
          <div
            key={item.id}
            className="shrink-0 first:pl-0 last:pr-0"
            style={{ scrollSnapAlign: "start" }}
          >
            <ShowcaseQuizCard
              id={item.id}
              title={item.title}
              badgeLabel={item.badgeLabel}
              durationLabel={item.durationLabel}
              playersLabel={item.playersLabel}
              accent={item.accent}
              coverImageUrl={item.coverImageUrl}
              href={item.href}
              priority={items.indexOf(item) < 3}
            />
          </div>
        ))}
      </div>

      {/* Navigation Arrows (Desktop Only) */}
      <div className="absolute top-1/2 -translate-y-1/2 left-0 right-0 pointer-events-none hidden lg:flex justify-between px-4 z-20">
        <Button
          variant="athletic"
          size="icon"
          className={cn(
            "pointer-events-auto rounded-none shadow-athletic transition-all duration-300",
            showLeftArrow ? "opacity-100 translate-x-0" : "opacity-0 -translate-x-4"
          )}
          onClick={() => scroll("left")}
        >
          <ChevronLeft className="h-6 w-6" />
        </Button>
        <Button
          variant="athletic"
          size="icon"
          className={cn(
            "pointer-events-auto rounded-none shadow-athletic transition-all duration-300",
            showRightArrow ? "opacity-100 translate-x-0" : "opacity-0 translate-x-4"
          )}
          onClick={() => scroll("right")}
        >
          <ChevronRight className="h-6 w-6" />
        </Button>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { cn } from "@/lib/utils";
import { Users, BookOpen, Loader2, ArrowRight } from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import type { TopicSummary } from "@/types/home";

interface TopTopicsResponse {
  topics: TopicSummary[];
  sortBy: string;
  limit: number;
  total: number;
}

interface ShowcaseTopTopicsProps {
  title?: string;
  showViewAll?: boolean;
  viewAllHref?: string;
  defaultSortBy?: "users" | "quizzes";
  limit?: number;
  className?: string;
  initialTopics?: TopicSummary[];
}

const topicIcons: Record<string, string> = {
  "default": "🏆",
};

const neonAccents = [
  { border: "border-primary/20", glow: "shadow-neon-cyan/20", text: "text-primary", bg: "bg-primary/5" },
  { border: "border-secondary/20", glow: "shadow-neon-magenta/20", text: "text-secondary", bg: "bg-secondary/5" },
  { border: "border-accent/20", glow: "shadow-neon-lime/20", text: "text-accent", bg: "bg-accent/5" },
];

export function ShowcaseTopTopics({
  title,
  showViewAll = true,
  viewAllHref = "/topics",
  defaultSortBy = "users",
  limit = 6,
  className,
  initialTopics,
}: ShowcaseTopTopicsProps) {
  const initialTopicsProvided = Array.isArray(initialTopics) && initialTopics.length > 0;
  const [topics, setTopics] = useState<TopicSummary[]>(initialTopics ?? []);
  const [sortBy, setSortBy] = useState<"users" | "quizzes">(defaultSortBy);
  const [loading, setLoading] = useState(!initialTopicsProvided);
  const hydratedInitialRef = useRef(false);

  useEffect(() => {
    if (!hydratedInitialRef.current) {
      hydratedInitialRef.current = true;
      if (initialTopicsProvided && sortBy === defaultSortBy) {
        setLoading(false);
        return;
      }
    }

    let ignore = false;
    const fetchTopTopics = async () => {
      try {
        setLoading(true);
        const response = await fetch(`/api/topics/top?sortBy=${sortBy}&limit=${limit}`);
        if (!response.ok) throw new Error(`Failed to fetch topics`);
        const data: TopTopicsResponse = await response.json();
        if (!ignore) setTopics(data.topics ?? []);
      } catch (err) {
        console.error("Failed to fetch topics", err);
      } finally {
        if (!ignore) setLoading(false);
      }
    };
    void fetchTopTopics();
    return () => { ignore = true; };
  }, [sortBy, limit, initialTopicsProvided, defaultSortBy]);

  if (loading) return (
    <div className="flex h-64 items-center justify-center">
      <Loader2 className="h-12 w-12 animate-spin text-primary" />
    </div>
  );

  return (
    <div className={cn("space-y-8", className)}>
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
        {title && (
          <h2 className="text-2xl font-black tracking-tight uppercase">{title}</h2>
        )}

        <div className="flex items-center gap-3 w-full sm:w-auto">
          <Select value={sortBy} onValueChange={(v: any) => setSortBy(v)}>
            <SelectTrigger className="glass-elevated border-white/10 h-11 min-w-[160px] font-bold uppercase tracking-widest text-[10px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent className="glass-elevated border-white/10">
              <SelectItem value="users" className="font-bold uppercase tracking-widest text-[10px]">Top Players</SelectItem>
              <SelectItem value="quizzes" className="font-bold uppercase tracking-widest text-[10px]">Massive Libraries</SelectItem>
            </SelectContent>
          </Select>

          {showViewAll && (
            <Button asChild variant="glass" size="lg" className="h-11 font-black uppercase tracking-widest text-[10px]">
              <Link href={viewAllHref}>Explore All</Link>
            </Button>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {topics.map((topic, index) => {
          const accent = neonAccents[index % neonAccents.length];

          return (
            <Link key={topic.id} href={`/topics/${topic.slug}`} className="group block">
              <Card className={cn(
                "relative overflow-hidden transition-all duration-300",
                "glass-elevated border-white/5 hover:border-white/10 hover:-translate-y-2 hover:shadow-glass-lg",
                accent.glow
              )}>
                <CardContent className="p-8">
                  <div className="flex items-start gap-6">
                    <div className={cn(
                      "relative h-16 w-16 shrink-0 rounded-2xl flex items-center justify-center text-3xl",
                      "glass border-white/10 shadow-sm",
                      "group-hover:scale-110 transition-transform duration-300"
                    )}>
                      {topic.imageUrl ? (
                        <Image
                          src={topic.imageUrl}
                          alt={topic.name}
                          fill
                          sizes="64px"
                          className="rounded-2xl object-cover p-1"
                          placeholder="empty"
                        />
                      ) : (
                        <span>{topicIcons.default}</span>
                      )}
                    </div>

                    <div className="flex-1 space-y-3">
                      <div className="space-y-1">
                        <h3 className="text-xl font-black tracking-tight leading-none group-hover:text-primary transition-colors">
                          {topic.name}
                        </h3>
                        <p className="text-xs text-muted-foreground font-medium line-clamp-1">
                          {topic.description}
                        </p>
                      </div>

                      <div className="flex items-center gap-4">
                        <div className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest text-muted-foreground">
                          <Users className={cn("h-3 w-3", accent.text)} />
                          {topic.userCount.toLocaleString()}
                        </div>
                        <div className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest text-muted-foreground">
                          <BookOpen className={cn("h-3 w-3", accent.text)} />
                          {topic.quizCount} Quizzes
                        </div>
                      </div>
                    </div>
                  </div>
                </CardContent>

                <div className={cn("absolute bottom-0 left-0 h-1 w-0 group-hover:w-full transition-all duration-500", accent.bg.replace('/5', ''))} />
              </Card>
            </Link>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useSearchParams, useRouter, usePathname } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";
import { Award, X, Sparkles, Trophy, Star } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import confetti from "canvas-confetti";

export function BadgeCelebration() {
    const searchParams = useSearchParams();
    const router = useRouter();
    const pathname = usePathname();
    const [badges, setBadges] = useState<string[]>([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [isOpen, setIsOpen] = useState(false);

    const triggerConfetti = () => {
        const duration = 3000;
        const end = Date.now() + duration;

        const frame = () => {
            confetti({
                particleCount: 2,
                angle: 60,
                spread: 55,
                origin: { x: 0 },
                colors: ["#10b981", "#3b82f6", "#f59e0b"]
            });
            confetti({
                particleCount: 2,
                angle: 120,
                spread: 55,
                origin: { x: 1 },
                colors: ["#10b981", "#3b82f6", "#f59e0b"]
            });

            if (Date.now() < end) {
                requestAnimationFrame(frame);
            }
        };
        frame();
    };

    useEffect(() => {
        const badgeParam = searchParams.get("badges");
        if (badgeParam) {
            const badgeNames = badgeParam.split(",").filter(Boolean);
            if (badgeNames.length > 0) {
                setBadges(badgeNames);
                setIsOpen(true);
                triggerConfetti();
            }
        }
    }, [searchParams]);

    const handleNext = () => {
        if (currentIndex < badges.length - 1) {
            setCurrentIndex((prev) => prev + 1);
            triggerConfetti();
        } else {
            handleClose();
        }
    };

    const handleClose = () => {
        setIsOpen(false);
        // Remove query param without refreshing
        const params = new URLSearchParams(searchParams.toString());
        params.delete("badges");
        router.replace(`${pathname}?${params.toString()}`, { scroll: false });
    };

    if (!isOpen || badges.length === 0) return null;

    const currentBadgeName = badges[currentIndex];

    return (
        <AnimatePresence>
            {isOpen && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4"
                >
                    <motion.div
                        initial={{ scale: 0.5, opacity: 0, y: 50 }}
                        animate={{ scale: 1, opacity: 1, y: 0 }}
                        exit={{ scale: 0.8, opacity: 0, y: 50 }}
                        className="w-full max-w-sm rounded-[2.5rem] bg-gradient-to-b from-slate-900 to-slate-950 border border-white/10 p-1 shadow-2xl overflow-hidden"
                    >
                        <div className="relative p-8 flex flex-col items-center text-center space-y-6">
                            {/* Background Effects */}
                            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-amber-500/10 via-transparent to-transparent pointer-events-none" />

                            {/* Close Button */}
                            <button
                                onClick={handleClose}
                                className="absolute top-4 right-4 p-2 rounded-full hover:bg-white/5 transition-colors"
                            >
                                <X className="w-5 h-5 text-muted-foreground" />
                            </button>

                            {/* Header */}
                            <div className="space-y-1 relative">
                                <motion.div
                                    initial={{ y: -20, opacity: 0 }}
                                    animate={{ y: 0, opacity: 1 }}
                                    transition={{ delay: 0.2 }}
                                    className="flex items-center justify-center gap-2 text-amber-500 font-bold uppercase tracking-widest text-xs"
                                >
                                    <Star className="w-3 h-3 fill-current" />
                                    New Achievement Unlocked
                                    <Star className="w-3 h-3 fill-current" />
                                </motion.div>
                            </div>

                            {/* Badge Icon */}
                            <motion.div
                                key={currentBadgeName}
                                initial={{ scale: 0, rotate: -180 }}
                                animate={{ scale: 1, rotate: 0 }}
                                transition={{ type: "spring", damping: 12, stiffness: 100, delay: 0.1 }}
                                className="relative w-32 h-32 flex items-center justify-center"
                            >
                                <div className="absolute inset-0 rounded-full bg-gradient-to-tr from-amber-500/20 to-purple-500/20 blur-xl animate-pulse" />
                                <div className="relative w-24 h-24 rounded-2xl bg-gradient-to-br from-amber-500 to-orange-600 flex items-center justify-center shadow-lg shadow-amber-500/20 rotate-6 ring-4 ring-black/20">
                                    <Trophy className="w-12 h-12 text-white drop-shadow-md" />
                                </div>
                            </motion.div>

                            {/* Badge Details */}
                            <div className="space-y-2 relative">
                                <motion.h2
                                    key={currentBadgeName + "title"}
                                    initial={{ y: 20, opacity: 0 }}
                                    animate={{ y: 0, opacity: 1 }}
                                    className="text-2xl font-black text-white tracking-tight"
                                >
                                    {decodeURIComponent(currentBadgeName)}
                                </motion.h2>
                                <motion.p
                                    initial={{ opacity: 0 }}
                                    animate={{ opacity: 1 }}
                                    transition={{ delay: 0.3 }}
                                    className="text-sm text-slate-400 font-medium"
                                >
                                    You&apos;ve proven your skills on the field.
                                </motion.p>
                            </div>

                            {/* Actions */}
                            <div className="w-full pt-4 space-y-3">
                                <Button
                                    onClick={handleNext}
                                    className="w-full h-12 rounded-xl bg-white text-slate-950 font-bold hover:bg-slate-200 transition-all text-base shadow-[0_0_20px_rgba(255,255,255,0.2)] hover:shadow-[0_0_30px_rgba(255,255,255,0.3)] hover:scale-[1.02] active:scale-[0.98]"
                                >
                                    {currentIndex < badges.length - 1 ? "Next Reward ->" : "Awesome!"}
                                </Button>

                                {currentIndex === badges.length - 1 && (
                                    <button
                                        onClick={() => router.push("/profile/me")}
                                        className="text-xs font-bold text-slate-500 hover:text-white uppercase tracking-widest transition-colors"
                                    >
                                        View Collection
                                    </button>
                                )}
                            </div>
                        </div>
                    </motion.div>
                </motion.div>
            )}
        </AnimatePresence>
    );
}

